package co.edu.uptc.simuladorautomatas.Dto;

import java.util.List;

public class AutomataDto {
    public String tipo;
    public List<String> alfabeto;
    public List<EstadoDto> estados;
    public List<TransicionDto> transiciones;
}

package co.edu.uptc.simuladorautomatas.Dto;

public class EstadoDto {
    public String nombre;
    public boolean esInicial;
    public boolean esAceptacion;
    public double x;
    public double y;
}

package co.edu.uptc.simuladorautomatas.Dto;

public class TransicionDto {
    public String origen;
    public String simbolo;
    public String destino;
}

package co.edu.uptc.simuladorautomatas.controller;

import co.edu.uptc.simuladorautomatas.logic.AutomataEvaluator;
import co.edu.uptc.simuladorautomatas.logic.AutomataValidator;
import co.edu.uptc.simuladorautomatas.logic.EvaluacionCadenaResultado;
import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import co.edu.uptc.simuladorautomatas.persistence.AutomataJsonRepository;

import java.io.IOException;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;

public class AutomataController {
    private final AutomataEvaluator evaluator;
    private final AutomataValidator validator;
    private final AutomataJsonRepository repository;
    private Automata automataActual;

    public AutomataController() {
        this.evaluator = new AutomataEvaluator();
        this.validator = new AutomataValidator();
        this.repository = new AutomataJsonRepository();
        this.automataActual = new Automata(TipoAutomata.DFA);
    }

    public Automata getAutomataActual() {
        return automataActual;
    }

    public void nuevoAutomata(TipoAutomata tipo, List<String> alfabeto) {
        this.automataActual = new Automata(tipo);
        this.automataActual.setAlfabeto(alfabeto);
    }

    public void reiniciarAutomata() {
        this.automataActual = new Automata(TipoAutomata.DFA);
        this.automataActual.setAlfabeto(List.of());
    }

    public void agregarEstado(String nombre, boolean inicial, boolean aceptacion, double x, double y) {
        Estado estado = new Estado(nombre, inicial, aceptacion, x, y);
        automataActual.agregarEstado(estado);
    }

    public void marcarInicial(String nombreEstado) {
        Estado estado = buscarEstado(nombreEstado);
        automataActual.marcarInicial(estado);
    }

    public void alternarAceptacion(String nombreEstado) {
        Estado estado = buscarEstado(nombreEstado);
        automataActual.alternarAceptacion(estado);
    }

    public void agregarTransicion(String origen, String simbolo, String destino) {
        Estado estadoOrigen = buscarEstado(origen);
        Estado estadoDestino = buscarEstado(destino);
        automataActual.agregarTransicion(new Transicion(estadoOrigen, simbolo.trim(), estadoDestino));
    }

    public List<EvaluacionCadenaResultado> evaluarLote(List<String> cadenas) {
        List<String> entradas = cadenas.stream().map(String::trim).filter(s -> !s.isEmpty()).toList();
        return evaluator.evaluarLote(automataActual, entradas);
    }

    public List<EvaluacionCadenaResultado> evaluarLoteConTraza(List<String> cadenas) {
        List<String> entradas = cadenas.stream().map(String::trim).filter(s -> !s.isEmpty()).toList();
        return evaluator.evaluarLote(automataActual, entradas, true);
    }

    public EvaluacionCadenaResultado evaluarConTraza(String cadena) {
        return evaluator.evaluar(automataActual, cadena, true);
    }

    public void validarAutomata() {
        validator.validar(automataActual);
    }

    public void guardar(Path path) throws IOException {
        repository.guardar(path, automataActual);
    }

    public void cargar(Path path) throws IOException {
        automataActual = repository.cargar(path);
    }

    public List<String> nombresEstados() {
        List<String> nombres = new ArrayList<>();
        automataActual.getEstados().forEach(e -> nombres.add(e.getNombre()));
        return nombres;
    }

    public void eliminarEstado(String nombreEstado) {
        Estado estado = buscarEstado(nombreEstado);
        automataActual.eliminarEstado(estado);
    }

    private Estado buscarEstado(String nombre) {
        return automataActual.buscarEstadoPorNombre(nombre)
                .orElseThrow(() -> new IllegalArgumentException("Estado no encontrado: " + nombre));
    }
}

package co.edu.uptc.simuladorautomatas.controller;

import co.edu.uptc.simuladorautomatas.logic.AutomataEvaluator;
import co.edu.uptc.simuladorautomatas.logic.AutomataValidator;
import co.edu.uptc.simuladorautomatas.logic.EvaluacionCadenaResultado;
import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.SimbolosAutomata;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import co.edu.uptc.simuladorautomatas.persistence.AutomataJsonRepository;

import java.io.IOException;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;

public class AutomataController {
    private final AutomataEvaluator evaluator;
    private final AutomataValidator validator;
    private final AutomataJsonRepository repository;
    private Automata automataActual;

    public AutomataController() {
        this.evaluator = new AutomataEvaluator();
        this.validator = new AutomataValidator();
        this.repository = new AutomataJsonRepository();
        this.automataActual = new Automata(TipoAutomata.DFA);
    }

    public Automata getAutomataActual() {
        return automataActual;
    }

    public void nuevoAutomata(TipoAutomata tipo, List<String> alfabeto) {
        this.automataActual = new Automata(tipo);
        this.automataActual.setAlfabeto(alfabeto);
    }

    public void reiniciarAutomata() {
        this.automataActual = new Automata(TipoAutomata.DFA);
        this.automataActual.setAlfabeto(List.of());
    }

    public void agregarEstado(String nombre, boolean inicial, boolean aceptacion, double x, double y) {
        Estado estado = new Estado(nombre, inicial, aceptacion, x, y);
        automataActual.agregarEstado(estado);
    }

    public void marcarInicial(String nombreEstado) {
        Estado estado = buscarEstado(nombreEstado);
        automataActual.marcarInicial(estado);
    }

    public void alternarAceptacion(String nombreEstado) {
        Estado estado = buscarEstado(nombreEstado);
        automataActual.alternarAceptacion(estado);
    }

    public void agregarTransicion(String origen, String simbolo, String destino) {
        Estado estadoOrigen = buscarEstado(origen);
        Estado estadoDestino = buscarEstado(destino);
        String simboloNormalizado = SimbolosAutomata.normalizarSimboloTransicion(simbolo);
        automataActual.agregarTransicion(new Transicion(estadoOrigen, simboloNormalizado, estadoDestino));
    }

    public List<EvaluacionCadenaResultado> evaluarLote(List<String> cadenas) {
        List<String> entradas = cadenas.stream().map(SimbolosAutomata::normalizarCadenaEntrada).toList();
        return evaluator.evaluarLote(automataActual, entradas);
    }

    public List<EvaluacionCadenaResultado> evaluarLoteConTraza(List<String> cadenas) {
        List<String> entradas = cadenas.stream().map(SimbolosAutomata::normalizarCadenaEntrada).toList();
        return evaluator.evaluarLote(automataActual, entradas, true);
    }

    public EvaluacionCadenaResultado evaluarConTraza(String cadena) {
        return evaluator.evaluar(automataActual, SimbolosAutomata.normalizarCadenaEntrada(cadena), true);
    }

    public void validarAutomata() {
        validator.validar(automataActual);
    }

    public void guardar(Path path) throws IOException {
        repository.guardar(path, automataActual);
    }

    public void cargar(Path path) throws IOException {
        automataActual = repository.cargar(path);
    }

    public List<String> nombresEstados() {
        List<String> nombres = new ArrayList<>();
        automataActual.getEstados().forEach(e -> nombres.add(e.getNombre()));
        return nombres;
    }

    public void eliminarEstado(String nombreEstado) {
        Estado estado = buscarEstado(nombreEstado);
        automataActual.eliminarEstado(estado);
    }

    private Estado buscarEstado(String nombre) {
        return automataActual.buscarEstadoPorNombre(nombre)
                .orElseThrow(() -> new IllegalArgumentException("Estado no encontrado: " + nombre));
    }
}

package co.edu.uptc.simuladorautomatas.logic;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;

import java.util.ArrayList;
import java.util.Collection;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class AutomataEvaluator {

    private final AutomataValidator validator;

    public AutomataEvaluator() {
        this.validator = new AutomataValidator();
    }

    public EvaluacionCadenaResultado evaluar(Automata automata, String cadena, boolean incluirTraza) {
        validator.validar(automata);
        String valor = cadena == null ? "" : cadena.trim();
        if (automata.getTipo() == TipoAutomata.DFA) {
            return evaluarDfa(automata, valor, incluirTraza);
        }
        return evaluarNfa(automata, valor, incluirTraza);
    }

    public List<EvaluacionCadenaResultado> evaluarLote(Automata automata, List<String> cadenas) {
        return evaluarLote(automata, cadenas, false);
    }

    public List<EvaluacionCadenaResultado> evaluarLote(Automata automata, List<String> cadenas, boolean incluirTraza) {
        if (cadenas.size() > 10) {
            throw new IllegalArgumentException("Solo se permiten hasta 10 cadenas por lote");
        }
        List<EvaluacionCadenaResultado> resultados = new ArrayList<>();
        for (String cadena : cadenas) {
            resultados.add(evaluar(automata, cadena, incluirTraza));
        }
        return resultados;
    }

    private EvaluacionCadenaResultado evaluarDfa(Automata automata, String cadena, boolean incluirTraza) {
        Estado actual = automata.getEstadoInicial();
        List<String> estadosIniciales = List.of(actual.getNombre());
        List<PasoEvaluacion> pasos = new ArrayList<>();

        StringBuilder traza = new StringBuilder(actual.getNombre());

        for (char simbolo : cadena.toCharArray()) {
            String valor = String.valueOf(simbolo);
            Estado siguiente = null;
            for (Transicion transicion : automata.getTransiciones()) {
                if (transicion.getEstadoOrigen().equals(actual) && transicion.getSimbolo().equals(valor)) {
                    siguiente = transicion.getEstadoDestino();
                    break;
                }
            }

            List<String> origen = List.of(actual.getNombre());
            List<String> destino = siguiente == null ? List.of() : List.of(siguiente.getNombre());
            pasos.add(new PasoEvaluacion(valor, origen, destino));

            if (siguiente == null) {
                if (incluirTraza) {
                    traza.append(" -> (").append(actual.getNombre()).append(", ").append(valor)
                            .append(") -> {}");
                }
                return new EvaluacionCadenaResultado(cadena, false, incluirTraza ? traza.toString() : "", estadosIniciales, pasos);
            }

            if (incluirTraza) {
                traza.append(" -> (").append(actual.getNombre()).append(", ").append(valor).append(") -> ")
                        .append(siguiente.getNombre());
            }
            actual = siguiente;
        }

        return new EvaluacionCadenaResultado(
                cadena,
                actual.isEsAceptacion(),
                incluirTraza ? traza.toString() : "",
                estadosIniciales,
                pasos
        );
    }

    private EvaluacionCadenaResultado evaluarNfa(Automata automata, String cadena, boolean incluirTraza) {
        Set<Estado> actuales = new LinkedHashSet<>();
        actuales.add(automata.getEstadoInicial());

        List<String> estadosIniciales = nombresEstados(actuales);
        List<PasoEvaluacion> pasos = new ArrayList<>();

        StringBuilder traza = new StringBuilder("{").append(formatoConjunto(actuales)).append("}");

        for (char simbolo : cadena.toCharArray()) {
            String valor = String.valueOf(simbolo);
            Set<Estado> siguientes = new LinkedHashSet<>();
            for (Estado estado : actuales) {
                automata.getTransiciones().stream()
                        .filter(t -> t.getEstadoOrigen().equals(estado) && t.getSimbolo().equals(valor))
                        .map(Transicion::getEstadoDestino)
                        .forEach(siguientes::add);
            }

            pasos.add(new PasoEvaluacion(valor, nombresEstados(actuales), nombresEstados(siguientes)));

            if (incluirTraza) {
                traza.append(" -> (").append(formatoConjunto(actuales)).append(", ").append(valor).append(") -> {")
                        .append(formatoConjunto(siguientes)).append("}");
            }

            actuales = siguientes;
            if (actuales.isEmpty()) {
                return new EvaluacionCadenaResultado(cadena, false, incluirTraza ? traza.toString() : "", estadosIniciales, pasos);
            }
        }

        boolean aceptada = actuales.stream().anyMatch(Estado::isEsAceptacion);
        return new EvaluacionCadenaResultado(cadena, aceptada, incluirTraza ? traza.toString() : "", estadosIniciales, pasos);
    }

    private List<String> nombresEstados(Collection<Estado> estados) {
        return estados.stream().map(Estado::getNombre).toList();
    }

    private String formatoConjunto(Set<Estado> estados) {
        return estados.stream().map(Estado::getNombre).collect(Collectors.joining(","));
    }
}

package co.edu.uptc.simuladorautomatas.logic;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.SimbolosAutomata;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;

import java.util.ArrayList;
import java.util.Collection;
import java.util.Deque;
import java.util.ArrayDeque;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class AutomataEvaluator {

    private final AutomataValidator validator;

    public AutomataEvaluator() {
        this.validator = new AutomataValidator();
    }

    public EvaluacionCadenaResultado evaluar(Automata automata, String cadena, boolean incluirTraza) {
        validator.validar(automata);
        String valor = SimbolosAutomata.normalizarCadenaEntrada(cadena);
        if (automata.getTipo() == TipoAutomata.DFA) {
            return evaluarDfa(automata, valor, incluirTraza);
        }
        return evaluarNfa(automata, valor, incluirTraza);
    }

    public List<EvaluacionCadenaResultado> evaluarLote(Automata automata, List<String> cadenas) {
        return evaluarLote(automata, cadenas, false);
    }

    public List<EvaluacionCadenaResultado> evaluarLote(Automata automata, List<String> cadenas, boolean incluirTraza) {
        if (cadenas.size() > 10) {
            throw new IllegalArgumentException("Solo se permiten hasta 10 cadenas por lote");
        }
        List<EvaluacionCadenaResultado> resultados = new ArrayList<>();
        for (String cadena : cadenas) {
            resultados.add(evaluar(automata, cadena, incluirTraza));
        }
        return resultados;
    }

    private EvaluacionCadenaResultado evaluarDfa(Automata automata, String cadena, boolean incluirTraza) {
        Estado actual = automata.getEstadoInicial();
        List<String> estadosIniciales = List.of(actual.getNombre());
        List<PasoEvaluacion> pasos = new ArrayList<>();

        StringBuilder traza = new StringBuilder(actual.getNombre());

        for (char simbolo : cadena.toCharArray()) {
            String valor = String.valueOf(simbolo);
            Estado siguiente = null;
            for (Transicion transicion : automata.getTransiciones()) {
                if (transicion.getEstadoOrigen().equals(actual) && transicion.getSimbolo().equals(valor)) {
                    siguiente = transicion.getEstadoDestino();
                    break;
                }
            }

            List<String> origen = List.of(actual.getNombre());
            List<String> destino = siguiente == null ? List.of() : List.of(siguiente.getNombre());
            pasos.add(new PasoEvaluacion(valor, origen, destino));

            if (siguiente == null) {
                if (incluirTraza) {
                    traza.append(" -> (").append(actual.getNombre()).append(", ").append(valor)
                            .append(") -> {}");
                }
                return new EvaluacionCadenaResultado(cadena, false, incluirTraza ? traza.toString() : "", estadosIniciales, pasos);
            }

            if (incluirTraza) {
                traza.append(" -> (").append(actual.getNombre()).append(", ").append(valor).append(") -> ")
                        .append(siguiente.getNombre());
            }
            actual = siguiente;
        }

        return new EvaluacionCadenaResultado(
                cadena,
                actual.isEsAceptacion(),
                incluirTraza ? traza.toString() : "",
                estadosIniciales,
                pasos
        );
    }

    private EvaluacionCadenaResultado evaluarNfa(Automata automata, String cadena, boolean incluirTraza) {
        Set<Estado> iniciales = new LinkedHashSet<>();
        iniciales.add(automata.getEstadoInicial());
        Set<Estado> actuales = cierreEpsilon(automata, iniciales);

        List<String> estadosIniciales = nombresEstados(actuales);
        List<PasoEvaluacion> pasos = new ArrayList<>();

        StringBuilder traza = new StringBuilder("{").append(formatoConjunto(actuales)).append("}");

        for (char simbolo : cadena.toCharArray()) {
            String valor = String.valueOf(simbolo);
            Set<Estado> siguientes = new LinkedHashSet<>();
            for (Estado estado : actuales) {
                for (Transicion transicion : automata.getTransiciones()) {
                    String simboloTransicion = SimbolosAutomata.normalizarSimboloTransicion(transicion.getSimbolo());
                    if (transicion.getEstadoOrigen().equals(estado) && simboloTransicion.equals(valor)) {
                        siguientes.add(transicion.getEstadoDestino());
                    }
                }
            }

            siguientes = cierreEpsilon(automata, siguientes);

            pasos.add(new PasoEvaluacion(valor, nombresEstados(actuales), nombresEstados(siguientes)));

            if (incluirTraza) {
                traza.append(" -> (").append(formatoConjunto(actuales)).append(", ").append(valor).append(") -> {")
                        .append(formatoConjunto(siguientes)).append("}");
            }

            actuales = siguientes;
            if (actuales.isEmpty()) {
                return new EvaluacionCadenaResultado(cadena, false, incluirTraza ? traza.toString() : "", estadosIniciales, pasos);
            }
        }

        boolean aceptada = actuales.stream().anyMatch(Estado::isEsAceptacion);
        return new EvaluacionCadenaResultado(cadena, aceptada, incluirTraza ? traza.toString() : "", estadosIniciales, pasos);
    }

    private List<String> nombresEstados(Collection<Estado> estados) {
        return estados.stream().map(Estado::getNombre).toList();
    }

    private String formatoConjunto(Set<Estado> estados) {
        return estados.stream().map(Estado::getNombre).collect(Collectors.joining(","));
    }

    private Set<Estado> cierreEpsilon(Automata automata, Set<Estado> base) {
        Set<Estado> cierre = new LinkedHashSet<>(base);
        Deque<Estado> pendientes = new ArrayDeque<>(base);
        while (!pendientes.isEmpty()) {
            Estado actual = pendientes.pop();
            for (Transicion transicion : automata.getTransiciones()) {
                String simbolo = SimbolosAutomata.normalizarSimboloTransicion(transicion.getSimbolo());
                if (!transicion.getEstadoOrigen().equals(actual) || !SimbolosAutomata.esEpsilon(simbolo)) {
                    continue;
                }
                Estado destino = transicion.getEstadoDestino();
                if (cierre.add(destino)) {
                    pendientes.push(destino);
                }
            }
        }
        return cierre;
    }
}

package co.edu.uptc.simuladorautomatas.logic;

public class EvaluacionCadenaResultado {
    private final String cadena;
    private final boolean aceptada;
    private final String traza;

    public EvaluacionCadenaResultado(String cadena, boolean aceptada, String traza) {
        this.cadena = cadena;
        this.aceptada = aceptada;
        this.traza = traza;
    }

    public String getCadena() {
        return cadena;
    }

    public boolean isAceptada() {
        return aceptada;
    }

    public String getTraza() {
        return traza;
    }

    public String getEstadoTexto() {
        return aceptada ? "ACEPTADA" : "RECHAZADA";
    }
}

package co.edu.uptc.simuladorautomatas.logic;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class EvaluacionCadenaResultado {
    private final String cadena;
    private final boolean aceptada;
    private final String traza;
    private final List<String> estadosIniciales;
    private final List<PasoEvaluacion> pasos;

    public EvaluacionCadenaResultado(String cadena, boolean aceptada, String traza) {
        this(cadena, aceptada, traza, List.of(), List.of());
    }

    public EvaluacionCadenaResultado(
            String cadena,
            boolean aceptada,
            String traza,
            List<String> estadosIniciales,
            List<PasoEvaluacion> pasos
    ) {
        this.cadena = cadena;
        this.aceptada = aceptada;
        this.traza = traza;
        this.estadosIniciales = Collections.unmodifiableList(new ArrayList<>(estadosIniciales));
        this.pasos = Collections.unmodifiableList(new ArrayList<>(pasos));
    }

    public String getCadena() {
        return cadena;
    }

    public boolean isAceptada() {
        return aceptada;
    }

    public String getTraza() {
        return traza;
    }

    public List<String> getEstadosIniciales() {
        return estadosIniciales;
    }

    public List<PasoEvaluacion> getPasos() {
        return pasos;
    }

    public String getEstadoTexto() {
        return aceptada ? "ACEPTADA" : "RECHAZADA";
    }
}

package co.edu.uptc.simuladorautomatas.persistence;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.SimbolosAutomata;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

import java.io.IOException;
import java.io.Reader;
import java.io.Writer;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class AutomataJsonRepository {
    private final Gson gson;

    public AutomataJsonRepository() {
        this.gson = new GsonBuilder().setPrettyPrinting().create();
    }

    public void guardar(Path archivo, Automata automata) throws IOException {
        AutomataDto dto = toDto(automata);
        try (Writer writer = Files.newBufferedWriter(archivo)) {
            gson.toJson(dto, writer);
        }
    }

    public Automata cargar(Path archivo) throws IOException {
        try (Reader reader = Files.newBufferedReader(archivo)) {
            AutomataDto dto = gson.fromJson(reader, AutomataDto.class);
            if (dto == null) {
                throw new IOException("Archivo JSON vacio o invalido");
            }
            return fromDto(dto);
        }
    }

    private AutomataDto toDto(Automata automata) {
        AutomataDto dto = new AutomataDto();
        dto.tipo = automata.getTipo().name();
        dto.alfabeto = new ArrayList<>(automata.getAlfabeto());
        dto.estados = automata.getEstados().stream().map(e -> {
            EstadoDto estadoDto = new EstadoDto();
            estadoDto.nombre = e.getNombre();
            estadoDto.esInicial = e.isEsInicial();
            estadoDto.esAceptacion = e.isEsAceptacion();
            estadoDto.x = e.getX();
            estadoDto.y = e.getY();
            return estadoDto;
        }).toList();
        dto.transiciones = automata.getTransiciones().stream().map(t -> {
            TransicionDto transicionDto = new TransicionDto();
            transicionDto.origen = t.getEstadoOrigen().getNombre();
            transicionDto.simbolo = SimbolosAutomata.normalizarSimboloTransicion(t.getSimbolo());
            transicionDto.destino = t.getEstadoDestino().getNombre();
            return transicionDto;
        }).toList();
        return dto;
    }

    private Automata fromDto(AutomataDto dto) {
        Automata automata = new Automata(TipoAutomata.valueOf(dto.tipo));
        automata.setAlfabeto(dto.alfabeto == null ? List.of() : dto.alfabeto);

        Map<String, Estado> estadosPorNombre = new HashMap<>();
        if (dto.estados != null) {
            for (EstadoDto estadoDto : dto.estados) {
                Estado estado = new Estado(estadoDto.nombre, estadoDto.esInicial, estadoDto.esAceptacion, estadoDto.x, estadoDto.y);
                automata.agregarEstado(estado);
                estadosPorNombre.put(estado.getNombre(), estado);
            }
        }

        if (dto.transiciones != null) {
            for (TransicionDto transicionDto : dto.transiciones) {
                Estado origen = estadosPorNombre.get(transicionDto.origen);
                Estado destino = estadosPorNombre.get(transicionDto.destino);
                if (origen == null || destino == null) {
                    throw new IllegalStateException("Transicion con estado inexistente en JSON");
                }
                String simbolo = SimbolosAutomata.normalizarSimboloTransicion(transicionDto.simbolo);
                automata.agregarTransicion(new Transicion(origen, simbolo, destino));
            }
        }
        return automata;
    }

    private static class AutomataDto {
        String tipo;
        List<String> alfabeto;
        List<EstadoDto> estados;
        List<TransicionDto> transiciones;
    }

    private static class EstadoDto {
        String nombre;
        boolean esInicial;
        boolean esAceptacion;
        double x;
        double y;
    }

    private static class TransicionDto {
        String origen;
        String simbolo;
        String destino;
    }
}

package co.edu.uptc.simuladorautomatas.persistence;

import co.edu.uptc.simuladorautomatas.Dto.AutomataDto;
import co.edu.uptc.simuladorautomatas.Dto.EstadoDto;
import co.edu.uptc.simuladorautomatas.Dto.TransicionDto;
import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.SimbolosAutomata;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

import java.io.IOException;
import java.io.Reader;
import java.io.Writer;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class AutomataJsonRepository {
    private final Gson gson;

    public AutomataJsonRepository() {
        this.gson = new GsonBuilder().setPrettyPrinting().create();
    }

    public void guardar(Path archivo, Automata automata) throws IOException {
        AutomataDto dto = toDto(automata);
        try (Writer writer = Files.newBufferedWriter(archivo)) {
            gson.toJson(dto, writer);
        }
    }

    public Automata cargar(Path archivo) throws IOException {
        try (Reader reader = Files.newBufferedReader(archivo)) {
            AutomataDto dto = gson.fromJson(reader, AutomataDto.class);
            if (dto == null) {
                throw new IOException("Archivo JSON vacio o invalido");
            }
            return fromDto(dto);
        }
    }

    private AutomataDto toDto(Automata automata) {
        AutomataDto dto = new AutomataDto();
        dto.tipo = automata.getTipo().name();
        dto.alfabeto = List.copyOf(automata.getAlfabeto());
        dto.estados = automata.getEstados().stream().map(e -> {
            EstadoDto estadoDto = new EstadoDto();
            estadoDto.nombre = e.getNombre();
            estadoDto.esInicial = e.isEsInicial();
            estadoDto.esAceptacion = e.isEsAceptacion();
            estadoDto.x = e.getX();
            estadoDto.y = e.getY();
            return estadoDto;
        }).toList();
        dto.transiciones = automata.getTransiciones().stream().map(t -> {
            TransicionDto transicionDto = new TransicionDto();
            transicionDto.origen = t.getEstadoOrigen().getNombre();
            transicionDto.simbolo = SimbolosAutomata.normalizarSimboloTransicion(t.getSimbolo());
            transicionDto.destino = t.getEstadoDestino().getNombre();
            return transicionDto;
        }).toList();
        return dto;
    }

    private Automata fromDto(AutomataDto dto) {
        Automata automata = new Automata(TipoAutomata.valueOf(dto.tipo));
        automata.setAlfabeto(dto.alfabeto == null ? List.of() : dto.alfabeto);

        Map<String, Estado> estadosPorNombre = new HashMap<>();
        if (dto.estados != null) {
            for (EstadoDto estadoDto : dto.estados) {
                Estado estado = new Estado(estadoDto.nombre, estadoDto.esInicial, estadoDto.esAceptacion, estadoDto.x, estadoDto.y);
                automata.agregarEstado(estado);
                estadosPorNombre.put(estado.getNombre(), estado);
            }
        }

        if (dto.transiciones != null) {
            for (TransicionDto transicionDto : dto.transiciones) {
                Estado origen = estadosPorNombre.get(transicionDto.origen);
                Estado destino = estadosPorNombre.get(transicionDto.destino);
                if (origen == null || destino == null) {
                    throw new IllegalStateException("Transicion con estado inexistente en JSON");
                }
                String simbolo = SimbolosAutomata.normalizarSimboloTransicion(transicionDto.simbolo);
                automata.agregarTransicion(new Transicion(origen, simbolo, destino));
            }
        }
        return automata;
    }
}

package co.edu.uptc.simuladorautomatas.ui;

import co.edu.uptc.simuladorautomatas.controller.AutomataController;
import co.edu.uptc.simuladorautomatas.logic.EvaluacionCadenaResultado;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import javafx.animation.FadeTransition;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Parent;
import javafx.scene.control.*;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Pane;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;
import javafx.util.Duration;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

/**
 * AutomataView - Vista principal del simulador de autómatas.
 *
 * Esta clase coordina los componentes de la UI utilizando clases especializadas:
 * - AutomataViewUIBuilder: Construcción de paneles UI
 * - AutomataViewDrawing: Dibujado en canvas
 * - AutomataViewInteraction: Interacción con estados/transiciones
 * - AutomataViewSimulation: Simulación y evaluación
 * - AutomataViewFileOps: Operaciones de archivo
 */
public class AutomataView {
    private final Stage stage;
    private final AutomataController controller;

    // Componentes UI
    private Pane panelDibujo;
    private Label estadoProcesoLabel;
    private TextField alfabetoField;
    private TextArea palabrasArea;
    private ListView<EvaluacionCadenaResultado> resultadosLoteList;
    private Button btnSiguientePaso;
    private Button btnReproducir;
    private ComboBox<TipoAutomata> tipoCombo;
    private VBox panelConfiguracion;
    private VBox panelPruebas;
    private VBox[] stepBoxes = new VBox[4];

    // Clases de soporte
    private AutomataViewUIBuilder uiBuilder;
    private AutomataViewDrawing drawingEngine;
    private AutomataViewInteraction interactionHandler;
    private AutomataViewSimulation simulationManager;
    private AutomataViewFileOps fileOps;

    // Estados de UI
    private String estadoSeleccionadoCanvas;
    private String estadoArrastrandose;
    private double ultimaXMouse;
    private double ultimaYMouse;
    private boolean modoCrearEstado;
    private String estadoEnCreacion;
    private boolean nuevoEstadoInicial;
    private boolean nuevoEstadoAceptacion;

    public AutomataView(Stage stage) {
        this.stage = stage;
        this.controller = new AutomataController();
    }

    public Parent build() {
        BorderPane root = new BorderPane();
        root.getStyleClass().add("app-root-with-grid");
        root.setTop(crearHeader());
        root.setCenter(crearZonaPrincipal());
        return root;
    }

    private Parent crearHeader() {
        uiBuilder = new AutomataViewUIBuilder();
        return uiBuilder.crearHeader(() -> fileOps.confirmarReinicio());
    }

    private Parent crearZonaPrincipal() {
        BorderPane contenedor = new BorderPane();
        contenedor.setPadding(new Insets(12));

        // Toolbar izquierda
        VBox toolbar = uiBuilder.crearToolbarFlotante(
            this::activarModoCreacionEstado,
            this::activarModoCreacionTransicion,
            this::eliminarElementoSeleccionado,
            () -> fileOps.guardarAutomata(),
            () -> fileOps.cargarAutomata(),
            () -> fileOps.mostrarAyuda()
        );
        contenedor.setLeft(toolbar);
        BorderPane.setMargin(toolbar, new Insets(0, 8, 0, 0));

        // Canvas central
        panelDibujo = new Pane();
        panelDibujo.setPrefSize(900, 620);
        panelDibujo.getStyleClass().add("canvas-pane");
        panelDibujo.setOnMouseClicked(e -> onCanvasMouseClicked(e.getX(), e.getY()));
        panelDibujo.setOnMousePressed(e -> onCanvasMousePressed(e.getX(), e.getY()));
        panelDibujo.setOnMouseDragged(e -> onCanvasMouseDragged(e.getX(), e.getY()));
        panelDibujo.setOnMouseReleased(e -> onCanvasMouseReleased());
        panelDibujo.widthProperty().addListener((o, ol, nw) -> redibujar());
        panelDibujo.heightProperty().addListener((o, ol, nw) -> redibujar());

        FadeTransition fadeIn = new FadeTransition(Duration.millis(400), panelDibujo);
        fadeIn.setFromValue(0.8);
        fadeIn.setToValue(1.0);
        fadeIn.play();

        contenedor.setCenter(panelDibujo);

        // Panel detalles derecha
        inicializarComponentesUI();
        VBox[] panelConfigOut = new VBox[1];
        VBox[] panelPruebasOut = new VBox[1];

        StackPane panelDetalles = uiBuilder.crearPanelDetalles(
            tipoCombo, alfabetoField, this::crearNuevoAutomata,
            palabrasArea, this::evaluarPalabras,
            () -> palabrasArea.clear(),
            this::agregarEpsilon,
            resultadosLoteList, btnSiguientePaso, btnReproducir,
            this::avanzarSimulacionManual,
            this::reproducirDesdeInicio,
            estadoProcesoLabel,
            panelConfigOut, panelPruebasOut
        );

        panelConfiguracion = panelConfigOut[0];
        panelPruebas = panelPruebasOut[0];

        contenedor.setRight(panelDetalles);
        BorderPane.setMargin(panelDetalles, new Insets(0, 0, 0, 8));

        return contenedor;
    }

    private void inicializarComponentesUI() {
        tipoCombo = new ComboBox<>();
        alfabetoField = new TextField();
        palabrasArea = new TextArea();
        resultadosLoteList = new ListView<>();
        resultadosLoteList.setCellFactory(lv -> new ListCell<EvaluacionCadenaResultado>() {
            @Override
            protected void updateItem(EvaluacionCadenaResultado item, boolean empty) {
                super.updateItem(item, empty);
                if (empty || item == null) {
                    setText(null);
                } else {
                    String valorCadena = item.getCadena().isEmpty() ? "ε" : item.getCadena();
                    setText((getIndex() + 1) + ". " + valorCadena + " -> " + item.getEstadoTexto());
                }
            }
        });
        resultadosLoteList.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2) {
                reproducirCadenaSeleccionadaLote();
            }
        });
        btnSiguientePaso = new Button("Siguiente paso");
        btnReproducir = new Button("Reproducir");
        estadoProcesoLabel = new Label("Seleccione una cadena de los resultados");

        // Inicializar clases de soporte
        drawingEngine = new AutomataViewDrawing(panelDibujo);
        interactionHandler = new AutomataViewInteraction(controller, drawingEngine);
        simulationManager = new AutomataViewSimulation(controller);
        fileOps = new AutomataViewFileOps(stage, controller);

        // Callbacks
        interactionHandler.setOnStatusChange(this::redibujar);
        simulationManager.setRedrawCallback(this::redibujar);
        fileOps.setOnAutomataLoaded(this::onAutomataLoaded);
        fileOps.setOnAutomataReset(this::onAutomataReset);

        // Stepper
        uiBuilder.crearStepperVisual(stepBoxes);
    }

    // ======================== EVENT HANDLERS ========================

    private void onCanvasMouseClicked(double x, double y) {
        if (modoCrearEstado) {
            crearEstadoEnCanvas(x, y);
            return;
        }
        String estado = interactionHandler.seleccionarEstadoEnCanvas(x, y);
        if (estado != null) {
            estadoSeleccionadoCanvas = estado;
            mostrarInfoEstado("Estado seleccionado: " + estado);
            redibujar();
        } else {
            // Deseleccionar si se hace click en el vacío
            if (estadoSeleccionadoCanvas != null) {
                estadoSeleccionadoCanvas = null;
                redibujar();
            }
        }
    }

    private void onCanvasMousePressed(double x, double y) {
        if (modoCrearEstado || estadoEnCreacion != null) return;

        var estado = interactionHandler.encontrarEstadoEnPosicion(x, y);
        if (estado != null) {
            estadoArrastrandose = estado.getNombre();
            ultimaXMouse = x;
            ultimaYMouse = y;
        }
    }

    private void onCanvasMouseDragged(double x, double y) {
        if (estadoArrastrandose == null) return;

        var estado = controller.getAutomataActual().getEstados().stream()
            .filter(e -> e.getNombre().equals(estadoArrastrandose))
            .findFirst();

        if (estado.isPresent()) {
            double deltaX = (x - ultimaXMouse) / drawingEngine.getEscala();
            double deltaY = (y - ultimaYMouse) / drawingEngine.getEscala();

            double nuevaX = Math.max(46, Math.min(900 - 46, estado.get().getX() + deltaX));
            double nuevaY = Math.max(46, Math.min(620 - 46, estado.get().getY() + deltaY));

            estado.get().setX(nuevaX);
            estado.get().setY(nuevaY);

            ultimaXMouse = x;
            ultimaYMouse = y;
            redibujar();
        }
    }

    private void onCanvasMouseReleased() {
        if (estadoArrastrandose != null) {
            mostrarInfoEstado("Estado '" + estadoArrastrandose + "' movido");
            estadoArrastrandose = null;
        }
    }

    // ======================== AUTOMATA OPERATIONS ========================

    private void crearNuevoAutomata() {
        try {
            String alfabetoText = alfabetoField.getText().trim();
            if (alfabetoText.isEmpty()) {
                mostrarErrorEstado("Ingrese al menos un símbolo en el alfabeto (ej: a,b)");
                return;
            }

            List<String> alfabeto = Arrays.stream(alfabetoText.split(","))
                    .map(String::trim)
                    .filter(s -> !s.isEmpty())
                    .collect(Collectors.toList());

            if (alfabeto.isEmpty()) {
                mostrarErrorEstado("Ingrese al menos un símbolo en el alfabeto (ej: a,b)");
                return;
            }

            controller.nuevoAutomata(tipoCombo.getValue(), alfabeto);
            simulationManager.detenerSimulacion();
            redibujar();
            mostrarInfoEstado("Autómata " + tipoCombo.getValue() + " creado. Agregue estados con el toolbar.");
            uiBuilder.mostrarPanelPruebas(panelConfiguracion, panelPruebas);
            marcarPasoCompleto(1);
        } catch (Exception ex) {
            mostrarErrorEstado("Error: " + ex.getMessage());
        }
    }

    private void activarModoCreacionEstado() {
        interactionHandler.mostrarDialogoNuevoEstado(() -> {
            modoCrearEstado = true;
            mostrarInfoEstado("Click en canvas para ubicar el estado");
        });
    }

    private void activarModoCreacionTransicion() {
        interactionHandler.mostrarDialogoNuevaTransicion(() -> {
            redibujar();
            marcarPasoCompleto(3);
        });
    }

    private void eliminarElementoSeleccionado() {
        interactionHandler.eliminarEstado(estadoSeleccionadoCanvas);
        estadoSeleccionadoCanvas = null;
        redibujar();
    }

    private void crearEstadoEnCanvas(double x, double y) {
        String nombreEstado = interactionHandler.getEstadoEnCreacionNombre();
        if (nombreEstado == null || nombreEstado.isEmpty()) {
            mostrarErrorEstado("Ingrese el nombre del estado antes de hacer click");
            return;
        }
        try {
            interactionHandler.crearEstadoEnPosicion(
                nombreEstado,
                interactionHandler.isEstadoEnCreacionInicial(),
                interactionHandler.isEstadoEnCreacionAceptacion(),
                x, y);
            modoCrearEstado = false;
            estadoSeleccionadoCanvas = nombreEstado;
            interactionHandler.limpiarEstadoEnCreacion();
            redibujar();
            marcarPasoCompleto(2);
            mostrarInfoEstado("Estado '" + nombreEstado + "' creado");
        } catch (Exception ex) {
            mostrarErrorEstado(ex.getMessage());
        }
    }

    // ======================== EVALUATION ========================

    private void evaluarPalabras() {
        try {
            List<EvaluacionCadenaResultado> resultados = simulationManager.evaluarPalabras(palabrasArea.getText());
            resultadosLoteList.getItems().setAll(resultados);

            if (!resultados.isEmpty()) {
                resultadosLoteList.getSelectionModel().select(0);
            }

            long aceptadas = resultados.stream().filter(EvaluacionCadenaResultado::isAceptada).count();
            estadoProcesoLabel.getStyleClass().removeAll("status-ok", "status-error");
            estadoProcesoLabel.getStyleClass().add("status-ok");
            estadoProcesoLabel.setText("Evaluadas " + resultados.size() + " cadenas. " + aceptadas
                    + " aceptadas. Seleccione una para ver paso a paso.");
            marcarPasoCompleto(4);
        } catch (Exception ex) {
            mostrarErrorEstado(ex.getMessage());
        }
    }

    private void reproducirCadenaSeleccionadaLote() {
        EvaluacionCadenaResultado seleccionado = resultadosLoteList.getSelectionModel().getSelectedItem();
        if (seleccionado == null) {
            mostrarErrorEstado("Seleccione una cadena para ver su paso a paso");
            return;
        }

        simulationManager.iniciarSimulacion(seleccionado);
        String valorCadena = seleccionado.getCadena().isEmpty() ? "ε" : seleccionado.getCadena();
        estadoProcesoLabel.getStyleClass().removeAll("status-ok", "status-error");
        estadoProcesoLabel.getStyleClass().add(seleccionado.isAceptada() ? "status-ok" : "status-error");
        estadoProcesoLabel.setText("Cadena: " + valorCadena + " -> " + seleccionado.getEstadoTexto());
        btnSiguientePaso.setDisable(false);
        btnReproducir.setDisable(false);
        redibujar();
    }

    private void avanzarSimulacionManual() {
        simulationManager.avanzarManual();
        redibujar();
    }

    private void reproducirDesdeInicio() {
        simulationManager.reproducirDesdeInicio();
        redibujar();
    }

    // ======================== DRAWING ========================

    private void redibujar() {
        drawingEngine.redibujar(
            controller.getAutomataActual(),
            estadoSeleccionadoCanvas,
            simulationManager.getEstadosResaltados(),
            simulationManager.getEstadosFinales(),
            simulationManager.getUltimoResultado()
        );
    }

    // ======================== UI HELPERS ========================

    private void mostrarInfoEstado(String mensaje) {
        estadoProcesoLabel.setText(mensaje);
        estadoProcesoLabel.getStyleClass().removeAll("status-error");
        estadoProcesoLabel.getStyleClass().add("status-ok");
    }

    private void mostrarErrorEstado(String mensaje) {
        estadoProcesoLabel.setText(mensaje);
        estadoProcesoLabel.getStyleClass().removeAll("status-ok");
        estadoProcesoLabel.getStyleClass().add("status-error");
    }

    private void agregarEpsilon() {
        String actual = palabrasArea.getText();
        if (actual == null || actual.isBlank()) {
            palabrasArea.setText("ε");
        } else if (actual.endsWith("\n") || actual.endsWith("\r")) {
            palabrasArea.appendText("ε");
        } else {
            palabrasArea.appendText(System.lineSeparator() + "ε");
        }
        palabrasArea.requestFocus();
        palabrasArea.positionCaret(palabrasArea.getText().length());
    }

    private void marcarPasoCompleto(int paso) {
        if (stepBoxes != null && paso >= 1 && paso <= stepBoxes.length && stepBoxes[paso - 1] != null) {
            VBox stepBox = stepBoxes[paso - 1];
            stepBox.getStyleClass().add("completed");

            if (stepBox.getChildren().size() > 0 && stepBox.getChildren().get(0) instanceof Label) {
                Label num = (Label) stepBox.getChildren().get(0);
                num.getStyleClass().removeAll("active");
                num.getStyleClass().add("completed-number");
            }

            if (paso < stepBoxes.length && stepBoxes[paso] != null) {
                VBox nextStep = stepBoxes[paso];
                nextStep.getStyleClass().add("active");
                if (nextStep.getChildren().size() > 0 && nextStep.getChildren().get(0) instanceof Label) {
                    Label nextNum = (Label) nextStep.getChildren().get(0);
                    nextNum.getStyleClass().add("active");
                }
            }
        }
    }

    // ======================== FILE OPERATIONS CALLBACKS ========================

    private void onAutomataLoaded() {
        var automata = controller.getAutomataActual();
        tipoCombo.setValue(automata.getTipo());
        alfabetoField.setText(String.join(",", automata.getAlfabeto()));
        modoCrearEstado = false;
        estadoSeleccionadoCanvas = null;
        simulationManager.detenerSimulacion();
        simulationManager.limpiarResultados();
        uiBuilder.mostrarPanelPruebas(panelConfiguracion, panelPruebas);
        redibujar();
    }

    private void onAutomataReset() {
        modoCrearEstado = false;
        tipoCombo.setValue(TipoAutomata.DFA);
        alfabetoField.clear();
        palabrasArea.clear();
        resultadosLoteList.getItems().clear();
        estadoSeleccionadoCanvas = null;
        simulationManager.detenerSimulacion();
        btnSiguientePaso.setDisable(true);
        btnReproducir.setDisable(true);
        uiBuilder.mostrarPanelConfiguracion(panelConfiguracion, panelPruebas);
        reiniciarStepperVisual();
        redibujar();
    }

    private void reiniciarStepperVisual() {
        for (VBox stepBox : stepBoxes) {
            if (stepBox != null) {
                stepBox.getStyleClass().removeAll("completed", "active");
            }
        }
        if (stepBoxes[0] != null && stepBoxes[0].getChildren().size() > 0) {
            Label num = (Label) stepBoxes[0].getChildren().get(0);
            num.getStyleClass().add("active");
        }
    }
}

package co.edu.uptc.simuladorautomatas.ui;

import co.edu.uptc.simuladorautomatas.controller.AutomataController;
import co.edu.uptc.simuladorautomatas.logic.EvaluacionCadenaResultado;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import javafx.animation.FadeTransition;
import javafx.geometry.Insets;
import javafx.scene.Parent;
import javafx.scene.control.Button;
import javafx.scene.control.ComboBox;
import javafx.scene.control.Label;
import javafx.scene.control.ListCell;
import javafx.scene.control.ListView;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.Pane;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;
import javafx.util.Duration;

import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

/**
 * Vista principal del simulador de automatas.
 */
public class AutomataView {
    private static final double CANVAS_WIDTH = 900;
    private static final double CANVAS_HEIGHT = 620;
    private static final double MARGEN_ESTADO = 46;

    private final Stage stage;
    private final AutomataController controller;

    // Componentes UI
    private Pane panelDibujo;
    private Label estadoProcesoLabel;
    private TextField alfabetoField;
    private TextArea palabrasArea;
    private ListView<EvaluacionCadenaResultado> resultadosLoteList;
    private Button btnSiguientePaso;
    private Button btnReproducir;
    private ComboBox<TipoAutomata> tipoCombo;
    private VBox panelConfiguracion;
    private VBox panelPruebas;
    private final VBox[] stepBoxes = new VBox[4];

    // Clases de soporte
    private AutomataViewUIBuilder uiBuilder;
    private AutomataViewDrawing drawingEngine;
    private AutomataViewInteraction interactionHandler;
    private AutomataViewSimulation simulationManager;
    private AutomataViewFileOps fileOps;

    // Estado UI
    private String estadoSeleccionadoCanvas;
    private String estadoArrastrandose;
    private double ultimaXMouse;
    private double ultimaYMouse;
    private boolean modoCrearEstado;

    public AutomataView(Stage stage) {
        this.stage = stage;
        this.controller = new AutomataController();
    }

    public Parent build() {
        BorderPane root = new BorderPane();
        root.getStyleClass().add("app-root-with-grid");
        root.setTop(crearHeader());
        root.setCenter(crearZonaPrincipal());
        return root;
    }

    private Parent crearHeader() {
        uiBuilder = new AutomataViewUIBuilder();
        return uiBuilder.crearHeader(() -> fileOps.confirmarReinicio());
    }

    private Parent crearZonaPrincipal() {
        BorderPane contenedor = new BorderPane();
        contenedor.setPadding(new Insets(12));
        agregarToolbar(contenedor);
        configurarCanvas(contenedor);
        agregarPanelDerecho(contenedor);
        return contenedor;
    }

    private void agregarToolbar(BorderPane contenedor) {
        VBox toolbar = uiBuilder.crearToolbarFlotante(
                this::activarModoCreacionEstado,
                this::activarModoCreacionTransicion,
                this::eliminarElementoSeleccionado,
                () -> fileOps.guardarAutomata(),
                () -> fileOps.cargarAutomata(),
                () -> fileOps.mostrarAyuda()
        );
        contenedor.setLeft(toolbar);
        BorderPane.setMargin(toolbar, new Insets(0, 8, 0, 0));
    }

    private void configurarCanvas(BorderPane contenedor) {
        panelDibujo = new Pane();
        panelDibujo.setPrefSize(CANVAS_WIDTH, CANVAS_HEIGHT);
        panelDibujo.getStyleClass().add("canvas-pane");
        configurarEventosCanvas();
        animarEntradaCanvas();
        contenedor.setCenter(panelDibujo);
    }

    private void configurarEventosCanvas() {
        panelDibujo.setOnMouseClicked(e -> onCanvasMouseClicked(e.getX(), e.getY()));
        panelDibujo.setOnMousePressed(e -> onCanvasMousePressed(e.getX(), e.getY()));
        panelDibujo.setOnMouseDragged(e -> onCanvasMouseDragged(e.getX(), e.getY()));
        panelDibujo.setOnMouseReleased(e -> onCanvasMouseReleased());
        panelDibujo.widthProperty().addListener((o, ol, nw) -> redibujar());
        panelDibujo.heightProperty().addListener((o, ol, nw) -> redibujar());
    }

    private void animarEntradaCanvas() {
        FadeTransition fadeIn = new FadeTransition(Duration.millis(400), panelDibujo);
        fadeIn.setFromValue(0.8);
        fadeIn.setToValue(1.0);
        fadeIn.play();
    }

    private void agregarPanelDerecho(BorderPane contenedor) {
        inicializarComponentesUI();
        VBox[] panelConfigOut = new VBox[1];
        VBox[] panelPruebasOut = new VBox[1];

        StackPane panelDetalles = uiBuilder.crearPanelDetalles(
                tipoCombo, alfabetoField, this::crearNuevoAutomata,
                palabrasArea, this::evaluarPalabras,
                () -> palabrasArea.clear(), this::agregarEpsilon,
                resultadosLoteList, btnSiguientePaso, btnReproducir,
                this::avanzarSimulacionManual, this::reproducirDesdeInicio,
                estadoProcesoLabel, panelConfigOut, panelPruebasOut
        );

        panelConfiguracion = panelConfigOut[0];
        panelPruebas = panelPruebasOut[0];
        contenedor.setRight(panelDetalles);
        BorderPane.setMargin(panelDetalles, new Insets(0, 0, 0, 8));
    }

    private void inicializarComponentesUI() {
        crearControlesBase();
        configurarListaResultados();
        inicializarServicios();
        configurarCallbacks();
        uiBuilder.crearStepperVisual(stepBoxes);
    }

    private void crearControlesBase() {
        tipoCombo = new ComboBox<>();
        alfabetoField = new TextField();
        palabrasArea = new TextArea();
        resultadosLoteList = new ListView<>();
        btnSiguientePaso = new Button("Siguiente paso");
        btnReproducir = new Button("Reproducir");
        estadoProcesoLabel = new Label("Seleccione una cadena de los resultados");
    }

    private void configurarListaResultados() {
        resultadosLoteList.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(EvaluacionCadenaResultado item, boolean empty) {
                super.updateItem(item, empty);
                setText(obtenerTextoResultado(item, empty, getIndex()));
            }
        });
        resultadosLoteList.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2) {
                reproducirCadenaSeleccionadaLote();
            }
        });
    }

    private String obtenerTextoResultado(EvaluacionCadenaResultado item, boolean empty, int index) {
        if (empty || item == null) {
            return null;
        }
        String valorCadena = item.getCadena().isEmpty() ? "ε" : item.getCadena();
        return ("%d. %s -> %s").formatted(index + 1, valorCadena, item.getEstadoTexto());
    }

    private void inicializarServicios() {
        drawingEngine = new AutomataViewDrawing(panelDibujo);
        interactionHandler = new AutomataViewInteraction(controller, drawingEngine);
        simulationManager = new AutomataViewSimulation(controller);
        fileOps = new AutomataViewFileOps(stage, controller);
    }

    private void configurarCallbacks() {
        interactionHandler.setOnStatusChange(this::redibujar);
        simulationManager.setRedrawCallback(this::redibujar);
        fileOps.setOnAutomataLoaded(this::onAutomataLoaded);
        fileOps.setOnAutomataReset(this::onAutomataReset);
    }

    private void onCanvasMouseClicked(double x, double y) {
        if (modoCrearEstado) {
            crearEstadoEnCanvas(x, y);
            return;
        }
        manejarSeleccionEstado(x, y);
    }

    private void manejarSeleccionEstado(double x, double y) {
        String estado = interactionHandler.seleccionarEstadoEnCanvas(x, y);
        if (estado == null) {
            limpiarSeleccionCanvas();
            return;
        }
        estadoSeleccionadoCanvas = estado;
        mostrarInfoEstado("Estado seleccionado: " + estado);
        redibujar();
    }

    private void limpiarSeleccionCanvas() {
        if (estadoSeleccionadoCanvas == null) {
            return;
        }
        estadoSeleccionadoCanvas = null;
        redibujar();
    }

    private void onCanvasMousePressed(double x, double y) {
        if (modoCrearEstado) {
            return;
        }
        var estado = interactionHandler.encontrarEstadoEnPosicion(x, y);
        if (estado == null) {
            return;
        }
        estadoArrastrandose = estado.getNombre();
        ultimaXMouse = x;
        ultimaYMouse = y;
    }

    private void onCanvasMouseDragged(double x, double y) {
        if (estadoArrastrandose == null) {
            return;
        }
        var estado = buscarEstadoArrastrado();
        estado.ifPresent(value -> moverEstado(value, x, y));
    }

    private java.util.Optional<co.edu.uptc.simuladorautomatas.model.Estado> buscarEstadoArrastrado() {
        return controller.getAutomataActual().getEstados().stream()
                .filter(e -> e.getNombre().equals(estadoArrastrandose))
                .findFirst();
    }

    private void moverEstado(co.edu.uptc.simuladorautomatas.model.Estado estado, double x, double y) {
        double deltaX = (x - ultimaXMouse) / drawingEngine.getEscala();
        double deltaY = (y - ultimaYMouse) / drawingEngine.getEscala();
        estado.setX(limitar(estado.getX() + deltaX, MARGEN_ESTADO, CANVAS_WIDTH - MARGEN_ESTADO));
        estado.setY(limitar(estado.getY() + deltaY, MARGEN_ESTADO, CANVAS_HEIGHT - MARGEN_ESTADO));
        ultimaXMouse = x;
        ultimaYMouse = y;
        redibujar();
    }

    private double limitar(double valor, double min, double max) {
        return Math.max(min, Math.min(max, valor));
    }

    private void onCanvasMouseReleased() {
        if (estadoArrastrandose == null) {
            return;
        }
        mostrarInfoEstado("Estado '" + estadoArrastrandose + "' movido");
        estadoArrastrandose = null;
    }

    private void crearNuevoAutomata() {
        try {
            List<String> alfabeto = construirAlfabeto();
            controller.nuevoAutomata(tipoCombo.getValue(), alfabeto);
            simulationManager.detenerSimulacion();
            mostrarAutmataCreado();
        } catch (Exception ex) {
            mostrarErrorEstado("Error: " + ex.getMessage());
        }
    }

    private List<String> construirAlfabeto() {
        String alfabetoText = alfabetoField.getText().trim();
        if (alfabetoText.isEmpty()) {
            throw new IllegalArgumentException("Ingrese al menos un símbolo en el alfabeto (ej: a,b)");
        }
        List<String> alfabeto = Arrays.stream(alfabetoText.split(","))
                .map(String::trim)
                .filter(s -> !s.isEmpty())
                .collect(Collectors.toList());
        if (alfabeto.isEmpty()) {
            throw new IllegalArgumentException("Ingrese al menos un símbolo en el alfabeto (ej: a,b)");
        }
        return alfabeto;
    }

    private void mostrarAutmataCreado() {
        redibujar();
        mostrarInfoEstado("Autómata " + tipoCombo.getValue() + " creado. Agregue estados con el toolbar.");
        uiBuilder.mostrarPanelPruebas(panelConfiguracion, panelPruebas);
        marcarPasoCompleto(1);
    }

    private void activarModoCreacionEstado() {
        interactionHandler.mostrarDialogoNuevoEstado(() -> {
            modoCrearEstado = true;
            mostrarInfoEstado("Click en canvas para ubicar el estado");
        });
    }

    private void activarModoCreacionTransicion() {
        interactionHandler.mostrarDialogoNuevaTransicion(() -> {
            redibujar();
            marcarPasoCompleto(3);
        });
    }

    private void eliminarElementoSeleccionado() {
        interactionHandler.eliminarEstado(estadoSeleccionadoCanvas);
        estadoSeleccionadoCanvas = null;
        redibujar();
    }

    private void crearEstadoEnCanvas(double x, double y) {
        String nombreEstado = interactionHandler.getEstadoEnCreacionNombre();
        if (nombreEstado == null || nombreEstado.isEmpty()) {
            mostrarErrorEstado("Ingrese el nombre del estado antes de hacer click");
            return;
        }
        crearEstadoYActualizarVista(nombreEstado, x, y);
    }

    private void crearEstadoYActualizarVista(String nombreEstado, double x, double y) {
        try {
            interactionHandler.crearEstadoEnPosicion(
                    nombreEstado,
                    interactionHandler.isEstadoEnCreacionInicial(),
                    interactionHandler.isEstadoEnCreacionAceptacion(),
                    x,
                    y
            );
            finalizarCreacionEstado(nombreEstado);
        } catch (Exception ex) {
            mostrarErrorEstado(ex.getMessage());
        }
    }

    private void finalizarCreacionEstado(String nombreEstado) {
        modoCrearEstado = false;
        estadoSeleccionadoCanvas = nombreEstado;
        interactionHandler.limpiarEstadoEnCreacion();
        redibujar();
        marcarPasoCompleto(2);
        mostrarInfoEstado("Estado '" + nombreEstado + "' creado");
    }

    private void evaluarPalabras() {
        try {
            List<EvaluacionCadenaResultado> resultados = simulationManager.evaluarPalabras(palabrasArea.getText());
            actualizarResultadosEvaluacion(resultados);
        } catch (Exception ex) {
            mostrarErrorEstado(ex.getMessage());
        }
    }

    private void actualizarResultadosEvaluacion(List<EvaluacionCadenaResultado> resultados) {
        resultadosLoteList.getItems().setAll(resultados);
        seleccionarPrimerResultado(resultados);
        long aceptadas = resultados.stream().filter(EvaluacionCadenaResultado::isAceptada).count();
        mostrarMensajeEvaluacion(resultados.size(), aceptadas);
        marcarPasoCompleto(4);
    }

    private void seleccionarPrimerResultado(List<EvaluacionCadenaResultado> resultados) {
        if (!resultados.isEmpty()) {
            resultadosLoteList.getSelectionModel().select(0);
        }
    }

    private void mostrarMensajeEvaluacion(int total, long aceptadas) {
        limpiarEstilosEstadoProceso();
        estadoProcesoLabel.getStyleClass().add("status-ok");
        estadoProcesoLabel.setText("Evaluadas " + total + " cadenas. " + aceptadas
                + " aceptadas. Seleccione una para ver paso a paso.");
    }

    private void reproducirCadenaSeleccionadaLote() {
        EvaluacionCadenaResultado seleccionado = resultadosLoteList.getSelectionModel().getSelectedItem();
        if (seleccionado == null) {
            mostrarErrorEstado("Seleccione una cadena para ver su paso a paso");
            return;
        }
        iniciarReproduccionSeleccionada(seleccionado);
    }

    private void iniciarReproduccionSeleccionada(EvaluacionCadenaResultado seleccionado) {
        simulationManager.iniciarSimulacion(seleccionado);
        String valorCadena = seleccionado.getCadena().isEmpty() ? "ε" : seleccionado.getCadena();
        limpiarEstilosEstadoProceso();
        estadoProcesoLabel.getStyleClass().add(seleccionado.isAceptada() ? "status-ok" : "status-error");
        estadoProcesoLabel.setText("Cadena: " + valorCadena + " -> " + seleccionado.getEstadoTexto());
        btnSiguientePaso.setDisable(false);
        btnReproducir.setDisable(false);
        redibujar();
    }

    private void avanzarSimulacionManual() {
        simulationManager.avanzarManual();
        redibujar();
    }

    private void reproducirDesdeInicio() {
        simulationManager.reproducirDesdeInicio();
        redibujar();
    }

    private void redibujar() {
        drawingEngine.redibujar(
                controller.getAutomataActual(),
                estadoSeleccionadoCanvas,
                simulationManager.getEstadosResaltados(),
                simulationManager.getEstadosFinales(),
                simulationManager.getUltimoResultado()
        );
    }

    private void mostrarInfoEstado(String mensaje) {
        estadoProcesoLabel.setText(mensaje);
        estadoProcesoLabel.getStyleClass().removeAll("status-error");
        estadoProcesoLabel.getStyleClass().add("status-ok");
    }

    private void mostrarErrorEstado(String mensaje) {
        estadoProcesoLabel.setText(mensaje);
        estadoProcesoLabel.getStyleClass().removeAll("status-ok");
        estadoProcesoLabel.getStyleClass().add("status-error");
    }

    private void limpiarEstilosEstadoProceso() {
        estadoProcesoLabel.getStyleClass().removeAll("status-ok", "status-error");
    }

    private void agregarEpsilon() {
        String actual = palabrasArea.getText();
        if (actual == null || actual.isBlank()) {
            palabrasArea.setText("ε");
        } else if (actual.endsWith("\n") || actual.endsWith("\r")) {
            palabrasArea.appendText("ε");
        } else {
            palabrasArea.appendText(System.lineSeparator() + "ε");
        }
        palabrasArea.requestFocus();
        palabrasArea.positionCaret(palabrasArea.getText().length());
    }

    private void marcarPasoCompleto(int paso) {
        if (!esPasoValido(paso)) {
            return;
        }
        marcarPasoActual(paso);
        activarPasoSiguiente(paso);
    }

    private boolean esPasoValido(int paso) {
        return stepBoxes != null && paso >= 1 && paso <= stepBoxes.length && stepBoxes[paso - 1] != null;
    }

    private void marcarPasoActual(int paso) {
        VBox stepBox = stepBoxes[paso - 1];
        stepBox.getStyleClass().add("completed");
        if (!(stepBox.getChildren().get(0) instanceof Label num)) {
            return;
        }
        num.getStyleClass().removeAll("active");
        num.getStyleClass().add("completed-number");
    }

    private void activarPasoSiguiente(int paso) {
        if (paso >= stepBoxes.length || stepBoxes[paso] == null) {
            return;
        }
        VBox nextStep = stepBoxes[paso];
        nextStep.getStyleClass().add("active");
        if (nextStep.getChildren().get(0) instanceof Label nextNum) {
            nextNum.getStyleClass().add("active");
        }
    }

    private void onAutomataLoaded() {
        var automata = controller.getAutomataActual();
        tipoCombo.setValue(automata.getTipo());
        alfabetoField.setText(String.join(",", automata.getAlfabeto()));
        modoCrearEstado = false;
        estadoSeleccionadoCanvas = null;
        simulationManager.detenerSimulacion();
        simulationManager.limpiarResultados();
        uiBuilder.mostrarPanelPruebas(panelConfiguracion, panelPruebas);
        redibujar();
    }

    private void onAutomataReset() {
        modoCrearEstado = false;
        tipoCombo.setValue(TipoAutomata.DFA);
        alfabetoField.clear();
        palabrasArea.clear();
        resultadosLoteList.getItems().clear();
        estadoSeleccionadoCanvas = null;
        simulationManager.detenerSimulacion();
        btnSiguientePaso.setDisable(true);
        btnReproducir.setDisable(true);
        uiBuilder.mostrarPanelConfiguracion(panelConfiguracion, panelPruebas);
        reiniciarStepperVisual();
        redibujar();
    }

    private void reiniciarStepperVisual() {
        for (VBox stepBox : stepBoxes) {
            if (stepBox != null) {
                stepBox.getStyleClass().removeAll("completed", "active");
            }
        }
        if (stepBoxes[0] != null && stepBoxes[0].getChildren().size() > 0) {
            Label num = (Label) stepBoxes[0].getChildren().get(0);
            num.getStyleClass().add("active");
        }
    }
}

package co.edu.uptc.simuladorautomatas.ui;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.SimbolosAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import javafx.scene.layout.Pane;
import javafx.scene.paint.Color;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Line;
import javafx.scene.shape.Polygon;
import javafx.scene.shape.QuadCurve;
import javafx.scene.shape.Rectangle;
import javafx.scene.text.Font;
import javafx.scene.text.Text;
import javafx.scene.layout.StackPane;
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

/**
 * Motor de dibujado: Responsable de renderizar estados, transiciones y etiquetas en el canvas.
 */
public class AutomataViewDrawing {
    private static final double RADIO_ESTADO = 30;
    private static final double CANVAS_LOGICAL_WIDTH = 900;
    private static final double CANVAS_LOGICAL_HEIGHT = 620;

    private Pane panelDibujo;
    private final List<double[]> zonasEtiquetasTransicion = new ArrayList<>();
    private double escala = 1.0;

    public AutomataViewDrawing(Pane panelDibujo) {
        this.panelDibujo = panelDibujo;
    }

    public void redibujar(Automata automata, String estadoSeleccionado,
                         Set<String> estadosResaltados, Set<String> estadosFinales,
                         Boolean ultimoResultadoAceptado) {
        panelDibujo.getChildren().clear();
        zonasEtiquetasTransicion.clear();
        calcularEscala();

        for (Transicion transicion : automata.getTransiciones()) {
            dibujarTransicion(transicion, estadoSeleccionado);
        }
        for (Estado estado : automata.getEstados()) {
            dibujarEstado(estado, estadoSeleccionado, estadosResaltados, estadosFinales, ultimoResultadoAceptado);
        }
    }

    private void dibujarEstado(Estado estado, String estadoSeleccionado,
                              Set<String> estadosResaltados, Set<String> estadosFinales,
                              Boolean ultimoResultadoAceptado) {
        boolean seleccionado = estado.getNombre().equals(estadoSeleccionado);
        boolean resaltado = estadosResaltados.contains(estado.getNombre());
        boolean estadoFinal = estadosFinales.contains(estado.getNombre());
        double x = logicoAVistaX(estado.getX());
        double y = logicoAVistaY(estado.getY());
        double radio = radioEscalado();

        // Halo brillante si está seleccionado
        if (seleccionado) {
            Circle halo = new Circle(x, y, radio + 12, Color.TRANSPARENT);
            halo.setStroke(Color.web("#2563EB"));
            halo.setStrokeWidth(2.0);
            halo.setStyle("-fx-stroke-dash-array: 4 2;");
            panelDibujo.getChildren().add(halo);

            Circle brillo = new Circle(x, y, radio + 6, Color.TRANSPARENT);
            brillo.setStroke(Color.web("rgba(37, 99, 235, 0.3)"));
            brillo.setStrokeWidth(3.0);
            panelDibujo.getChildren().add(brillo);
        }

        if (resaltado) {
            Circle haloEvaluacion = new Circle(x, y, radio + 9, Color.TRANSPARENT);
            haloEvaluacion.setStroke(Color.web("#F59E0B"));
            haloEvaluacion.setStrokeWidth(2.4);
            panelDibujo.getChildren().add(haloEvaluacion);
        }

        if (estadoFinal && ultimoResultadoAceptado != null) {
            Circle haloFinal = new Circle(x, y, radio + 10, Color.TRANSPARENT);
            haloFinal.setStroke(ultimoResultadoAceptado ? Color.web("#16A34A") : Color.web("#DC2626"));
            haloFinal.setStrokeWidth(2.8);
            panelDibujo.getChildren().add(haloFinal);
        }

        Color colorBase = resaltado ? Color.web("#FEF3C7") : Color.web("#F8FAFC");
        if (estadoFinal && ultimoResultadoAceptado != null) {
            colorBase = ultimoResultadoAceptado ? Color.web("#DCFCE7") : Color.web("#FEE2E2");
        }

        Circle principal = new Circle(x, y, radio, colorBase);
        principal.setStroke(seleccionado ? Color.web("#2563EB") : Color.web("#1F2937"));
        principal.setStrokeWidth(seleccionado ? 3.0 : 1.7);

        if (estado.isEsInicial() && !estadoFinal) {
            principal.setFill(resaltado ? Color.web("#FDE68A") : Color.web("#E0F2FE"));
        }

        panelDibujo.getChildren().add(principal);

        if (estado.isEsAceptacion()) {
            Circle interno = new Circle(x, y, radio - 6, Color.TRANSPARENT);
            interno.setStroke(seleccionado ? Color.web("#2563EB") : Color.web("#059669"));
            interno.setStrokeWidth(1.8);
            panelDibujo.getChildren().add(interno);
        }

        if (estado.isEsInicial()) {
            Line flecha = new Line(x - (radio + 32), y, x - radio, y);
            flecha.setStroke(Color.web("#0F172A"));
            Polygon punta = new Polygon(
                    x - radio, y,
                    x - radio - 11, y - 6,
                    x - radio - 11, y + 6
            );
            punta.setFill(Color.web("#0F172A"));
            panelDibujo.getChildren().addAll(flecha, punta);
        }

        Text texto = new Text(estado.getNombre());
        texto.setFont(Font.font(14));
        texto.setFill(Color.web("#0F172A"));
        texto.setX(x - (texto.getLayoutBounds().getWidth() / 2));
        texto.setY(y + 4);
        panelDibujo.getChildren().add(texto);
    }

    private void dibujarTransicion(Transicion transicion, String estadoSeleccionado) {
        Estado origen = transicion.getEstadoOrigen();
        Estado destino = transicion.getEstadoDestino();
        double radio = radioEscalado();
        double ox = logicoAVistaX(origen.getX());
        double oy = logicoAVistaY(origen.getY());
        double dx = logicoAVistaX(destino.getX());
        double dy = logicoAVistaY(destino.getY());

        if (origen.equals(destino)) {
            Circle loop = new Circle(ox, oy - radio - 18, 16, Color.TRANSPARENT);
            loop.setStroke(Color.web("#334155"));
            loop.setStrokeWidth(1.6);
            Text etiqueta = new Text(formatearSimboloVisual(transicion.getSimbolo()));
            etiqueta.setFont(Font.font(13));
            double textoW = etiqueta.getLayoutBounds().getWidth();
            double textoH = etiqueta.getLayoutBounds().getHeight();
            double[] pos = ajustarPosicionEtiqueta(ox, oy - radio - 38, textoW, textoH, 0, -1);
            StackPane chip = crearChipEtiqueta(etiqueta, pos[0], pos[1]);
            panelDibujo.getChildren().addAll(loop, chip);
            return;
        }

        double deltaX = dx - ox;
        double deltaY = dy - oy;
        double longitud = Math.hypot(deltaX, deltaY);
        if (longitud == 0) return;

        double ux = deltaX / longitud;
        double uy = deltaY / longitud;
        double px = -uy;
        double py = ux;

        double inicioX = ox + ux * radio;
        double inicioY = oy + uy * radio;
        double finX = dx - ux * radio;
        double finY = dy - uy * radio;

        double curvatura = 18 + Math.min(26, longitud * 0.07);
        double controlX = (inicioX + finX) / 2 + px * curvatura;
        double controlY = (inicioY + finY) / 2 + py * curvatura;

        QuadCurve curva = new QuadCurve(inicioX, inicioY, controlX, controlY, finX, finY);
        curva.setFill(Color.TRANSPARENT);
        curva.setStroke(Color.web("#334155"));
        curva.setStrokeWidth(1.7);

        double tx = finX - controlX;
        double ty = finY - controlY;
        double tLen = Math.hypot(tx, ty);
        if (tLen == 0) return;

        double tux = tx / tLen;
        double tuy = ty / tLen;

        Polygon punta = new Polygon(
                finX, finY,
                finX - tux * 14 - tuy * 8, finY - tuy * 14 + tux * 8,
                finX - tux * 14 + tuy * 8, finY - tuy * 14 - tux * 8
        );
        punta.setFill(Color.web("#334155"));

        Text etiqueta = new Text(formatearSimboloVisual(transicion.getSimbolo()));
        etiqueta.setFont(Font.font(13));
        double textoW = etiqueta.getLayoutBounds().getWidth();
        double textoH = etiqueta.getLayoutBounds().getHeight();

        double medioX = (inicioX + (2 * controlX) + finX) / 4.0;
        double medioY = (inicioY + (2 * controlY) + finY) / 4.0;
        double etiquetaOffset = Math.max(14.0, radio * 0.45);
        double baseEtiquetaX = medioX + (px * etiquetaOffset);
        double baseEtiquetaY = medioY + (py * etiquetaOffset);
        double[] pos = ajustarPosicionEtiqueta(baseEtiquetaX, baseEtiquetaY, textoW, textoH, px, py);
        StackPane chip = crearChipEtiqueta(etiqueta, pos[0], pos[1]);

        panelDibujo.getChildren().addAll(curva, punta, chip);
    }

    private StackPane crearChipEtiqueta(Text etiquetaTexto, double centerX, double centerY) {
        etiquetaTexto.setFill(Color.web("#1D4ED8"));
        double textoW = etiquetaTexto.getLayoutBounds().getWidth();
        double textoH = etiquetaTexto.getLayoutBounds().getHeight();

        Rectangle fondo = new Rectangle(textoW + 10, textoH + 6);
        fondo.setArcWidth(10);
        fondo.setArcHeight(10);
        fondo.setFill(Color.web("rgba(248, 250, 252, 0.95)"));
        fondo.setStroke(Color.web("#CBD5E1"));
        fondo.setStrokeWidth(0.7);

        StackPane chip = new StackPane(fondo, etiquetaTexto);
        chip.setLayoutX(centerX - ((textoW + 10) / 2));
        chip.setLayoutY(centerY - ((textoH + 6) / 2));
        return chip;
    }

    private double[] ajustarPosicionEtiqueta(double centerX, double centerY, double textoW, double textoH,
                                             double normalX, double normalY) {
        double x = centerX;
        double y = centerY;
        double ancho = textoW + 10;
        double alto = textoH + 6;

        for (int intento = 0; intento < 7; intento++) {
            double left = x - (ancho / 2.0);
            double top = y - (alto / 2.0);
            double right = left + ancho;
            double bottom = top + alto;

            if (!colisionaEtiqueta(left, top, right, bottom)) {
                zonasEtiquetasTransicion.add(new double[] {left, top, right, bottom});
                return new double[] {x, y};
            }

            double signo = (intento % 2 == 0) ? 1.0 : -1.0;
            double paso = 10 + (intento * 5);
            x += normalX * paso * signo;
            y += normalY * paso * signo;
        }

        double left = x - (ancho / 2.0);
        double top = y - (alto / 2.0);
        zonasEtiquetasTransicion.add(new double[] {left, top, left + ancho, top + alto});
        return new double[] {x, y};
    }

    private boolean colisionaEtiqueta(double left, double top, double right, double bottom) {
        for (double[] zona : zonasEtiquetasTransicion) {
            boolean separada = right < zona[0] || left > zona[2] || bottom < zona[1] || top > zona[3];
            if (!separada) {
                return true;
            }
        }
        return false;
    }

    private void calcularEscala() {
        if (panelDibujo.getWidth() <= 0 || panelDibujo.getHeight() <= 0) {
            escala = 1.0;
        } else {
            double sx = panelDibujo.getWidth() / CANVAS_LOGICAL_WIDTH;
            double sy = panelDibujo.getHeight() / CANVAS_LOGICAL_HEIGHT;
            escala = Math.max(0.72, Math.min(sx, sy));
        }
    }

    private double radioEscalado() {
        return RADIO_ESTADO * escala;
    }

    private double logicoAVistaX(double x) {
        return x * escala;
    }

    private double logicoAVistaY(double y) {
        return y * escala;
    }

    public double vistaALogicoX(double x) {
        return x / escala;
    }

    public double vistaALogicoY(double y) {
        return y / escala;
    }

    public double getRadioEscalado() {
        return radioEscalado();
    }

    public double getEscala() {
        return escala;
    }

    private String formatearSimboloVisual(String simbolo) {
        String normalizado = SimbolosAutomata.normalizarSimboloTransicion(simbolo);
        return SimbolosAutomata.esEpsilon(normalizado) ? SimbolosAutomata.EPSILON : normalizado;
    }
}

package co.edu.uptc.simuladorautomatas.ui;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.SimbolosAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import javafx.scene.layout.Pane;
import javafx.scene.paint.Color;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Line;
import javafx.scene.shape.Polygon;
import javafx.scene.shape.QuadCurve;
import javafx.scene.shape.Rectangle;
import javafx.scene.text.Font;
import javafx.scene.text.Text;
import javafx.scene.layout.StackPane;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

/**
 * Motor de dibujado: Responsable de renderizar estados, transiciones y etiquetas en el canvas.
 */
public class AutomataViewDrawing {
    private static final double RADIO_ESTADO = 30;
    private static final double CANVAS_LOGICAL_WIDTH = 900;
    private static final double CANVAS_LOGICAL_HEIGHT = 620;

    private Pane panelDibujo;
    private final List<double[]> zonasEtiquetasTransicion = new ArrayList<>();
    private double escala = 1.0;

    public AutomataViewDrawing(Pane panelDibujo) {
        this.panelDibujo = panelDibujo;
    }

    public void redibujar(Automata automata, String estadoSeleccionado,
                         Set<String> estadosResaltados, Set<String> estadosFinales,
                         Boolean ultimoResultadoAceptado) {
        panelDibujo.getChildren().clear();
        zonasEtiquetasTransicion.clear();
        calcularEscala();

        for (Map.Entry<AristaKey, String> entrada : agruparTransiciones(automata.getTransiciones()).entrySet()) {
            AristaKey arista = entrada.getKey();
            dibujarTransicion(arista.origen, arista.destino, entrada.getValue());
        }
        for (Estado estado : automata.getEstados()) {
            dibujarEstado(estado, estadoSeleccionado, estadosResaltados, estadosFinales, ultimoResultadoAceptado);
        }
    }

    private void dibujarEstado(Estado estado, String estadoSeleccionado,
                              Set<String> estadosResaltados, Set<String> estadosFinales,
                              Boolean ultimoResultadoAceptado) {
        boolean seleccionado = estado.getNombre().equals(estadoSeleccionado);
        boolean resaltado = estadosResaltados.contains(estado.getNombre());
        boolean estadoFinal = estadosFinales.contains(estado.getNombre());
        double x = logicoAVistaX(estado.getX());
        double y = logicoAVistaY(estado.getY());
        double radio = radioEscalado();

        // Halo brillante si está seleccionado
        if (seleccionado) {
            Circle halo = new Circle(x, y, radio + 12, Color.TRANSPARENT);
            halo.setStroke(Color.web("#2563EB"));
            halo.setStrokeWidth(2.0);
            halo.setStyle("-fx-stroke-dash-array: 4 2;");
            panelDibujo.getChildren().add(halo);

            Circle brillo = new Circle(x, y, radio + 6, Color.TRANSPARENT);
            brillo.setStroke(Color.web("rgba(37, 99, 235, 0.3)"));
            brillo.setStrokeWidth(3.0);
            panelDibujo.getChildren().add(brillo);
        }

        if (resaltado) {
            Circle haloEvaluacion = new Circle(x, y, radio + 9, Color.TRANSPARENT);
            haloEvaluacion.setStroke(Color.web("#F59E0B"));
            haloEvaluacion.setStrokeWidth(2.4);
            panelDibujo.getChildren().add(haloEvaluacion);
        }

        if (estadoFinal && ultimoResultadoAceptado != null) {
            Circle haloFinal = new Circle(x, y, radio + 10, Color.TRANSPARENT);
            haloFinal.setStroke(ultimoResultadoAceptado ? Color.web("#16A34A") : Color.web("#DC2626"));
            haloFinal.setStrokeWidth(2.8);
            panelDibujo.getChildren().add(haloFinal);
        }

        Color colorBase = resaltado ? Color.web("#FEF3C7") : Color.web("#F8FAFC");
        if (estadoFinal && ultimoResultadoAceptado != null) {
            colorBase = ultimoResultadoAceptado ? Color.web("#DCFCE7") : Color.web("#FEE2E2");
        }

        Circle principal = new Circle(x, y, radio, colorBase);
        principal.setStroke(seleccionado ? Color.web("#2563EB") : Color.web("#1F2937"));
        principal.setStrokeWidth(seleccionado ? 3.0 : 1.7);

        if (estado.isEsInicial() && !estadoFinal) {
            principal.setFill(resaltado ? Color.web("#FDE68A") : Color.web("#E0F2FE"));
        }

        panelDibujo.getChildren().add(principal);

        if (estado.isEsAceptacion()) {
            Circle interno = new Circle(x, y, radio - 6, Color.TRANSPARENT);
            interno.setStroke(seleccionado ? Color.web("#2563EB") : Color.web("#059669"));
            interno.setStrokeWidth(1.8);
            panelDibujo.getChildren().add(interno);
        }

        if (estado.isEsInicial()) {
            Line flecha = new Line(x - (radio + 32), y, x - radio, y);
            flecha.setStroke(Color.web("#0F172A"));
            Polygon punta = new Polygon(
                    x - radio, y,
                    x - radio - 11, y - 6,
                    x - radio - 11, y + 6
            );
            punta.setFill(Color.web("#0F172A"));
            panelDibujo.getChildren().addAll(flecha, punta);
        }

        Text texto = new Text(estado.getNombre());
        texto.setFont(Font.font(14));
        texto.setFill(Color.web("#0F172A"));
        texto.setX(x - (texto.getLayoutBounds().getWidth() / 2));
        texto.setY(y + 4);
        panelDibujo.getChildren().add(texto);
    }

    private void dibujarTransicion(Estado origen, Estado destino, String etiquetaSimbolos) {
        double radio = radioEscalado();
        double ox = logicoAVistaX(origen.getX());
        double oy = logicoAVistaY(origen.getY());
        double dx = logicoAVistaX(destino.getX());
        double dy = logicoAVistaY(destino.getY());

        if (origen.equals(destino)) {
            Circle loop = new Circle(ox, oy - radio - 18, 16, Color.TRANSPARENT);
            loop.setStroke(Color.web("#334155"));
            loop.setStrokeWidth(1.6);
            Text etiqueta = new Text(etiquetaSimbolos);
            etiqueta.setFont(Font.font(13));
            double textoW = etiqueta.getLayoutBounds().getWidth();
            double textoH = etiqueta.getLayoutBounds().getHeight();
            double[] pos = ajustarPosicionEtiqueta(ox, oy - radio - 38, textoW, textoH, 0, -1);
            StackPane chip = crearChipEtiqueta(etiqueta, pos[0], pos[1]);
            panelDibujo.getChildren().addAll(loop, chip);
            return;
        }

        double deltaX = dx - ox;
        double deltaY = dy - oy;
        double longitud = Math.hypot(deltaX, deltaY);
        if (longitud == 0) return;

        double ux = deltaX / longitud;
        double uy = deltaY / longitud;
        double px = -uy;
        double py = ux;

        double inicioX = ox + ux * radio;
        double inicioY = oy + uy * radio;
        double finX = dx - ux * radio;
        double finY = dy - uy * radio;

        double curvatura = 18 + Math.min(26, longitud * 0.07);
        double controlX = (inicioX + finX) / 2 + px * curvatura;
        double controlY = (inicioY + finY) / 2 + py * curvatura;

        QuadCurve curva = new QuadCurve(inicioX, inicioY, controlX, controlY, finX, finY);
        curva.setFill(Color.TRANSPARENT);
        curva.setStroke(Color.web("#334155"));
        curva.setStrokeWidth(1.7);

        double tx = finX - controlX;
        double ty = finY - controlY;
        double tLen = Math.hypot(tx, ty);
        if (tLen == 0) return;

        double tux = tx / tLen;
        double tuy = ty / tLen;

        Polygon punta = new Polygon(
                finX, finY,
                finX - tux * 14 - tuy * 8, finY - tuy * 14 + tux * 8,
                finX - tux * 14 + tuy * 8, finY - tuy * 14 - tux * 8
        );
        punta.setFill(Color.web("#334155"));

        Text etiqueta = new Text(etiquetaSimbolos);
        etiqueta.setFont(Font.font(13));
        double textoW = etiqueta.getLayoutBounds().getWidth();
        double textoH = etiqueta.getLayoutBounds().getHeight();

        double medioX = (inicioX + (2 * controlX) + finX) / 4.0;
        double medioY = (inicioY + (2 * controlY) + finY) / 4.0;
        double etiquetaOffset = Math.max(14.0, radio * 0.45);
        double baseEtiquetaX = medioX + (px * etiquetaOffset);
        double baseEtiquetaY = medioY + (py * etiquetaOffset);
        double[] pos = ajustarPosicionEtiqueta(baseEtiquetaX, baseEtiquetaY, textoW, textoH, px, py);
        StackPane chip = crearChipEtiqueta(etiqueta, pos[0], pos[1]);

        panelDibujo.getChildren().addAll(curva, punta, chip);
    }

    private Map<AristaKey, String> agruparTransiciones(List<Transicion> transiciones) {
        Map<AristaKey, LinkedHashSet<String>> agrupadas = new LinkedHashMap<>();
        for (Transicion transicion : transiciones) {
            AristaKey key = new AristaKey(transicion.getEstadoOrigen(), transicion.getEstadoDestino());
            String simbolo = formatearSimboloVisual(transicion.getSimbolo());
            agrupadas.computeIfAbsent(key, k -> new LinkedHashSet<>()).add(simbolo);
        }

        Map<AristaKey, String> etiquetas = new LinkedHashMap<>();
        for (Map.Entry<AristaKey, LinkedHashSet<String>> entrada : agrupadas.entrySet()) {
            etiquetas.put(entrada.getKey(), String.join(", ", entrada.getValue()));
        }
        return etiquetas;
    }

    private StackPane crearChipEtiqueta(Text etiquetaTexto, double centerX, double centerY) {
        etiquetaTexto.setFill(Color.web("#1D4ED8"));
        double textoW = etiquetaTexto.getLayoutBounds().getWidth();
        double textoH = etiquetaTexto.getLayoutBounds().getHeight();

        Rectangle fondo = new Rectangle(textoW + 10, textoH + 6);
        fondo.setArcWidth(10);
        fondo.setArcHeight(10);
        fondo.setFill(Color.web("rgba(248, 250, 252, 0.95)"));
        fondo.setStroke(Color.web("#CBD5E1"));
        fondo.setStrokeWidth(0.7);

        StackPane chip = new StackPane(fondo, etiquetaTexto);
        chip.setLayoutX(centerX - ((textoW + 10) / 2));
        chip.setLayoutY(centerY - ((textoH + 6) / 2));
        return chip;
    }

    private double[] ajustarPosicionEtiqueta(double centerX, double centerY, double textoW, double textoH,
                                             double normalX, double normalY) {
        double x = centerX;
        double y = centerY;
        double ancho = textoW + 10;
        double alto = textoH + 6;

        for (int intento = 0; intento < 7; intento++) {
            double left = x - (ancho / 2.0);
            double top = y - (alto / 2.0);
            double right = left + ancho;
            double bottom = top + alto;

            if (!colisionaEtiqueta(left, top, right, bottom)) {
                zonasEtiquetasTransicion.add(new double[] {left, top, right, bottom});
                return new double[] {x, y};
            }

            double signo = (intento % 2 == 0) ? 1.0 : -1.0;
            double paso = 10 + (intento * 5);
            x += normalX * paso * signo;
            y += normalY * paso * signo;
        }

        double left = x - (ancho / 2.0);
        double top = y - (alto / 2.0);
        zonasEtiquetasTransicion.add(new double[] {left, top, left + ancho, top + alto});
        return new double[] {x, y};
    }

    private boolean colisionaEtiqueta(double left, double top, double right, double bottom) {
        for (double[] zona : zonasEtiquetasTransicion) {
            boolean separada = right < zona[0] || left > zona[2] || bottom < zona[1] || top > zona[3];
            if (!separada) {
                return true;
            }
        }
        return false;
    }

    private void calcularEscala() {
        if (panelDibujo.getWidth() <= 0 || panelDibujo.getHeight() <= 0) {
            escala = 1.0;
        } else {
            double sx = panelDibujo.getWidth() / CANVAS_LOGICAL_WIDTH;
            double sy = panelDibujo.getHeight() / CANVAS_LOGICAL_HEIGHT;
            escala = Math.max(0.72, Math.min(sx, sy));
        }
    }

    private double radioEscalado() {
        return RADIO_ESTADO * escala;
    }

    private double logicoAVistaX(double x) {
        return x * escala;
    }

    private double logicoAVistaY(double y) {
        return y * escala;
    }

    public double vistaALogicoX(double x) {
        return x / escala;
    }

    public double vistaALogicoY(double y) {
        return y / escala;
    }

    public double getRadioEscalado() {
        return radioEscalado();
    }

    public double getEscala() {
        return escala;
    }

    private String formatearSimboloVisual(String simbolo) {
        String normalizado = SimbolosAutomata.normalizarSimboloTransicion(simbolo);
        return SimbolosAutomata.esEpsilon(normalizado) ? SimbolosAutomata.EPSILON : normalizado;
    }

    private static final class AristaKey {
        private final Estado origen;
        private final Estado destino;

        private AristaKey(Estado origen, Estado destino) {
            this.origen = origen;
            this.destino = destino;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) {
                return true;
            }
            if (!(o instanceof AristaKey that)) {
                return false;
            }
            return origen.equals(that.origen) && destino.equals(that.destino);
        }

        @Override
        public int hashCode() {
            return 31 * origen.hashCode() + destino.hashCode();
        }
    }
}

package co.edu.uptc.simuladorautomatas.ui;

import co.edu.uptc.simuladorautomatas.controller.AutomataController;
import javafx.scene.control.Alert;
import javafx.scene.control.ButtonType;
import javafx.stage.FileChooser;
import javafx.stage.Stage;
import java.io.File;
import java.util.Optional;

/**
 * Operaciones de archivo: guardar y cargar autómatas.
 */
public class AutomataViewFileOps {
    private final Stage stage;
    private final AutomataController controller;
    private Runnable onAutomataLoaded;
    private Runnable onAutomataReset;

    public AutomataViewFileOps(Stage stage, AutomataController controller) {
        this.stage = stage;
        this.controller = controller;
    }

    public void setOnAutomataLoaded(Runnable callback) {
        this.onAutomataLoaded = callback;
    }

    public void setOnAutomataReset(Runnable callback) {
        this.onAutomataReset = callback;
    }

    public void guardarAutomata() {
        FileChooser chooser = new FileChooser();
        chooser.setTitle("Guardar automata");
        chooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("JSON", "*.json"));
        File file = chooser.showSaveDialog(stage);
        if (file == null) {
            return;
        }
        try {
            controller.validarAutomata();
            controller.guardar(file.toPath());
            mostrarInfo("Automata guardado en " + file.getName());
        } catch (Exception ex) {
            mostrarError(ex.getMessage());
        }
    }

    public void cargarAutomata() {
        FileChooser chooser = new FileChooser();
        chooser.setTitle("Cargar automata");
        chooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("JSON", "*.json"));
        File file = chooser.showOpenDialog(stage);
        if (file == null) {
            return;
        }
        try {
            controller.cargar(file.toPath());
            mostrarInfo("Automata cargado: " + file.getName());
            if (onAutomataLoaded != null) {
                onAutomataLoaded.run();
            }
        } catch (Exception ex) {
            mostrarError(ex.getMessage());
        }
    }

    public void mostrarAyuda() {
        Alert ayuda = new Alert(Alert.AlertType.INFORMATION);
        ayuda.setTitle("Ayuda - Simulador de Autómatas");
        ayuda.setHeaderText("Manual de Uso");
        ayuda.setContentText(
            "SIMULADOR DE AUTÓMATAS FINITOS\n\n" +
            "1. CREAR AUTÓMATA:\n" +
            "   • Seleccione el tipo (DFA o NFA)\n" +
            "   • Defina el alfabeto separado por comas\n" +
            "   • Presione 'Crear Autómata'\n\n" +
            "2. AGREGAR ESTADOS:\n" +
            "   • Presione el botón ⊕ en la barra izquierda\n" +
            "   • Ingrese el nombre del estado\n" +
            "   • Seleccione si es inicial o final\n" +
            "   • Haga click en el canvas para ubicarlo\n\n" +
            "3. AGREGAR TRANSICIONES:\n" +
            "   • Presione el botón → en la barra izquierda\n" +
            "   • Seleccione estado origen y destino\n" +
            "   • Ingrese el símbolo del alfabeto (en NFA también puede usar ε/lambda)\n\n" +
            "4. ELIMINAR ELEMENTOS:\n" +
            "   • Presione el botón ✕ para eliminar un estado\n" +
            "   • Seleccione el estado a eliminar\n\n" +
            "5. EVALUAR CADENAS:\n" +
            "   • Use el panel derecho para ingresar palabras\n" +
            "   • Presione 'Evaluar Todas' para probar múltiples cadenas\n\n" +
            "6. GUARDAR Y CARGAR:\n" +
            "   • Use los botones en la barra izquierda\n" +
            "   • Los archivos se guardan en formato JSON"
        );
        ayuda.showAndWait();
    }

    public void confirmarReinicio() {
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Reiniciar automata");
        confirm.setHeaderText("Se eliminarán estados, transiciones y entradas");
        confirm.setContentText("¿Desea continuar?");
        Optional<ButtonType> respuesta = confirm.showAndWait();
        if (respuesta.isPresent() && respuesta.get() == ButtonType.OK) {
            reiniciarAutomata();
        }
    }

    public void reiniciarAutomata() {
        try {
            controller.reiniciarAutomata();
            if (onAutomataReset != null) {
                onAutomataReset.run();
            }
            mostrarInfo("Lienzo limpio. Defina un nuevo automata");
        } catch (Exception ex) {
            mostrarError(ex.getMessage());
        }
    }

    private void mostrarError(String mensaje) {
        Alert alert = new Alert(Alert.AlertType.ERROR);
        alert.setTitle("Error");
        alert.setHeaderText("Operación no válida");
        alert.setContentText(mensaje);
        alert.showAndWait();
    }

    private void mostrarInfo(String mensaje) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION);
        alert.setTitle("Información");
        alert.setHeaderText("Operación completada");
        alert.setContentText(mensaje);
        alert.showAndWait();
    }
}

package co.edu.uptc.simuladorautomatas.ui;

import co.edu.uptc.simuladorautomatas.controller.AutomataController;
import javafx.geometry.Insets;
import javafx.scene.control.Alert;
import javafx.scene.control.ButtonType;
import javafx.scene.control.Dialog;
import javafx.scene.control.Label;
import javafx.scene.control.ScrollPane;
import javafx.scene.control.Separator;
import javafx.scene.layout.VBox;
import javafx.stage.FileChooser;
import javafx.stage.Stage;
import java.io.File;
import java.util.Optional;

/**
 * Operaciones de archivo: guardar y cargar autómatas.
 */
public class AutomataViewFileOps {
    private final Stage stage;
    private final AutomataController controller;
    private Runnable onAutomataLoaded;
    private Runnable onAutomataReset;

    public AutomataViewFileOps(Stage stage, AutomataController controller) {
        this.stage = stage;
        this.controller = controller;
    }

    public void setOnAutomataLoaded(Runnable callback) {
        this.onAutomataLoaded = callback;
    }

    public void setOnAutomataReset(Runnable callback) {
        this.onAutomataReset = callback;
    }

    public void guardarAutomata() {
        FileChooser chooser = new FileChooser();
        chooser.setTitle("Guardar automata");
        chooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("JSON", "*.json"));
        File file = chooser.showSaveDialog(stage);
        if (file == null) {
            return;
        }
        try {
            controller.validarAutomata();
            controller.guardar(file.toPath());
            mostrarInfo("Automata guardado en " + file.getName());
        } catch (Exception ex) {
            mostrarError(ex.getMessage());
        }
    }

    public void cargarAutomata() {
        FileChooser chooser = new FileChooser();
        chooser.setTitle("Cargar automata");
        chooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("JSON", "*.json"));
        File file = chooser.showOpenDialog(stage);
        if (file == null) {
            return;
        }
        try {
            controller.cargar(file.toPath());
            mostrarInfo("Automata cargado: " + file.getName());
            if (onAutomataLoaded != null) {
                onAutomataLoaded.run();
            }
        } catch (Exception ex) {
            mostrarError(ex.getMessage());
        }
    }

    public void mostrarAyuda() {
        Dialog<Void> ayuda = new Dialog<>();
        ayuda.setTitle("Ayuda - Simulador de Automatas");
        ayuda.setHeaderText("Guia rapida de uso");
        ayuda.getDialogPane().getButtonTypes().add(ButtonType.CLOSE);

        VBox contenido = new VBox(12);
        contenido.setPadding(new Insets(8, 4, 8, 4));
        contenido.getChildren().addAll(
                crearSeccionAyuda("1) Crear automata",
                        "Seleccione el tipo (DFA o NFA)",
                        "Defina el alfabeto separado por comas",
                        "Pulse 'Crear Automata'"),
                new Separator(),
                crearSeccionAyuda("2) Agregar estados",
                        "Pulse el boton de estado en la barra izquierda",
                        "Ingrese nombre y marque inicial/final si aplica",
                        "Haga click en el canvas para ubicarlo"),
                new Separator(),
                crearSeccionAyuda("3) Agregar transiciones",
                        "Pulse el boton de transicion",
                        "Seleccione origen, simbolo y destino",
                        "En NFA puede usar epsilon con el boton e o dejando vacio el simbolo"),
                new Separator(),
                crearSeccionAyuda("4) Evaluar y simular",
                        "Ingrese una palabra por linea en el panel derecho",
                        "Pulse 'Evaluar Todas'",
                        "Seleccione un resultado y use 'Siguiente paso' o 'Reproducir'"),
                new Separator(),
                crearSeccionAyuda("5) Guardar y cargar",
                        "Use los botones de guardar/cargar en la barra izquierda",
                        "El formato de archivo es JSON")
        );

        ScrollPane scroll = new ScrollPane(contenido);
        scroll.setFitToWidth(true);
        scroll.setPrefViewportHeight(420);
        scroll.setPrefViewportWidth(520);

        ayuda.getDialogPane().setContent(scroll);
        ayuda.showAndWait();
    }

    private VBox crearSeccionAyuda(String titulo, String... puntos) {
        Label tituloLabel = new Label(titulo);
        tituloLabel.setStyle("-fx-font-size: 13px; -fx-font-weight: bold; -fx-text-fill: #1F2937;");

        VBox seccion = new VBox(6);
        seccion.getChildren().add(tituloLabel);
        for (String punto : puntos) {
            Label linea = new Label("• " + punto);
            linea.setWrapText(true);
            linea.setStyle("-fx-font-size: 12px; -fx-text-fill: #334155;");
            seccion.getChildren().add(linea);
        }
        return seccion;
    }

    public void confirmarReinicio() {
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Reiniciar automata");
        confirm.setHeaderText("Se eliminarán estados, transiciones y entradas");
        confirm.setContentText("¿Desea continuar?");
        Optional<ButtonType> respuesta = confirm.showAndWait();
        if (respuesta.isPresent() && respuesta.get() == ButtonType.OK) {
            reiniciarAutomata();
        }
    }

    public void reiniciarAutomata() {
        try {
            controller.reiniciarAutomata();
            if (onAutomataReset != null) {
                onAutomataReset.run();
            }
            mostrarInfo("Lienzo limpio. Defina un nuevo automata");
        } catch (Exception ex) {
            mostrarError(ex.getMessage());
        }
    }

    private void mostrarError(String mensaje) {
        Alert alert = new Alert(Alert.AlertType.ERROR);
        alert.setTitle("Error");
        alert.setHeaderText("Operación no válida");
        alert.setContentText(mensaje);
        alert.showAndWait();
    }

    private void mostrarInfo(String mensaje) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION);
        alert.setTitle("Información");
        alert.setHeaderText("Operación completada");
        alert.setContentText(mensaje);
        alert.showAndWait();
    }
}

package co.edu.uptc.simuladorautomatas.logic;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import co.edu.uptc.simuladorautomatas.persistence.AutomataJsonRepository;
import org.junit.jupiter.api.Test;

import java.nio.file.Path;
import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class AutomataEvaluatorTest {

    private final AutomataEvaluator evaluator = new AutomataEvaluator();

    @Test
    void dfaParCerosAceptaYRechaza() throws Exception {
        AutomataJsonRepository repository = new AutomataJsonRepository();
        Path archivo = Path.of("src", "main", "resources", "test-data", "dfa_binario_par_0.json");
        Automata automata = repository.cargar(archivo);

        assertTrue(evaluator.evaluar(automata, "11", false).isAceptada());
        assertTrue(!evaluator.evaluar(automata, "10", false).isAceptada());
    }

    @Test
    void nfaBasicoFuncionaConTraza() {
        Automata nfa = new Automata(TipoAutomata.NFA);
        nfa.setAlfabeto(List.of("a", "b"));

        Estado q0 = new Estado("q0", true, false, 0, 0);
        Estado q1 = new Estado("q1", false, true, 0, 0);
        nfa.agregarEstado(q0);
        nfa.agregarEstado(q1);
        nfa.agregarTransicion(new Transicion(q0, "a", q0));
        nfa.agregarTransicion(new Transicion(q0, "a", q1));
        nfa.agregarTransicion(new Transicion(q1, "b", q1));

        EvaluacionCadenaResultado resultado = evaluator.evaluar(nfa, "aab", true);
        assertTrue(resultado.isAceptada());
        assertTrue(resultado.getTraza().contains("(q0, a)"));
    }

    @Test
    void evaluacionLoteLimitaADiez() {
        Automata dfa = new Automata(TipoAutomata.DFA);
        dfa.setAlfabeto(List.of("a"));
        Estado q0 = new Estado("q0", true, true, 0, 0);
        dfa.agregarEstado(q0);
        dfa.agregarTransicion(new Transicion(q0, "a", q0));

        List<EvaluacionCadenaResultado> resultados = evaluator.evaluarLote(dfa, List.of("", "a", "aa"));
        assertEquals(3, resultados.size());
        assertTrue(resultados.stream().allMatch(EvaluacionCadenaResultado::isAceptada));
    }
}

package co.edu.uptc.simuladorautomatas.logic;

import co.edu.uptc.simuladorautomatas.model.Automata;
import co.edu.uptc.simuladorautomatas.model.Estado;
import co.edu.uptc.simuladorautomatas.model.TipoAutomata;
import co.edu.uptc.simuladorautomatas.model.Transicion;
import co.edu.uptc.simuladorautomatas.persistence.AutomataJsonRepository;
import org.junit.jupiter.api.Test;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

class AutomataEvaluatorTest {

    private final AutomataEvaluator evaluator = new AutomataEvaluator();

    @Test
    void dfaParCerosAceptaYRechaza() throws Exception {
        AutomataJsonRepository repository = new AutomataJsonRepository();
        Path archivo = Path.of("src", "main", "resources", "test-data", "dfa_binario_par_0.json");
        Automata automata = repository.cargar(archivo);

        assertTrue(evaluator.evaluar(automata, "11", false).isAceptada());
        assertTrue(!evaluator.evaluar(automata, "10", false).isAceptada());
    }

    @Test
    void nfaBasicoFuncionaConTraza() {
        Automata nfa = new Automata(TipoAutomata.NFA);
        nfa.setAlfabeto(List.of("a", "b"));

        Estado q0 = new Estado("q0", true, false, 0, 0);
        Estado q1 = new Estado("q1", false, true, 0, 0);
        nfa.agregarEstado(q0);
        nfa.agregarEstado(q1);
        nfa.agregarTransicion(new Transicion(q0, "a", q0));
        nfa.agregarTransicion(new Transicion(q0, "a", q1));
        nfa.agregarTransicion(new Transicion(q1, "b", q1));

        EvaluacionCadenaResultado resultado = evaluator.evaluar(nfa, "aab", true);
        assertTrue(resultado.isAceptada());
        assertTrue(resultado.getTraza().contains("(q0, a)"));
    }

    @Test
    void evaluacionLoteLimitaADiez() {
        Automata dfa = new Automata(TipoAutomata.DFA);
        dfa.setAlfabeto(List.of("a"));
        Estado q0 = new Estado("q0", true, true, 0, 0);
        dfa.agregarEstado(q0);
        dfa.agregarTransicion(new Transicion(q0, "a", q0));

        List<EvaluacionCadenaResultado> resultados = evaluator.evaluarLote(dfa, List.of("", "a", "aa"));
        assertEquals(3, resultados.size());
        assertTrue(resultados.stream().allMatch(EvaluacionCadenaResultado::isAceptada));
    }

    @Test
    void palabraVaciaSePuedeIngresarComoEpsilonOLambda() {
        Automata dfa = new Automata(TipoAutomata.DFA);
        dfa.setAlfabeto(List.of("a"));
        Estado q0 = new Estado("q0", true, true, 0, 0);
        dfa.agregarEstado(q0);
        dfa.agregarTransicion(new Transicion(q0, "a", q0));

        assertTrue(evaluator.evaluar(dfa, "epsilon", false).isAceptada());
        assertTrue(evaluator.evaluar(dfa, "lambda", false).isAceptada());
        assertTrue(evaluator.evaluar(dfa, "\u03b5", false).isAceptada());
    }

    @Test
    void nfaConTransicionEpsilonEvaluaCierreYdFARechazaEpsilon() {
        Automata nfa = new Automata(TipoAutomata.NFA);
        nfa.setAlfabeto(List.of("a"));

        Estado q0 = new Estado("q0", true, false, 0, 0);
        Estado q1 = new Estado("q1", false, true, 0, 0);
        nfa.agregarEstado(q0);
        nfa.agregarEstado(q1);
        nfa.agregarTransicion(new Transicion(q0, "epsilon", q1));

        assertTrue(evaluator.evaluar(nfa, "", false).isAceptada());
        assertTrue(evaluator.evaluar(nfa, "\u03b5", false).isAceptada());

        Automata dfa = new Automata(TipoAutomata.DFA);
        dfa.setAlfabeto(List.of("a"));
        Estado d0 = new Estado("d0", true, false, 0, 0);
        Estado d1 = new Estado("d1", false, true, 0, 0);
        dfa.agregarEstado(d0);
        dfa.agregarEstado(d1);

        IllegalArgumentException error = assertThrows(
                IllegalArgumentException.class,
                () -> dfa.agregarTransicion(new Transicion(d0, "lambda", d1))
        );
        assertFalse(error.getMessage().isBlank());
    }

    @Test
    void persistenciaJsonMantieneTransicionEpsilon() throws Exception {
        Automata nfa = new Automata(TipoAutomata.NFA);
        nfa.setAlfabeto(List.of("a", "epsilon"));

        Estado q0 = new Estado("q0", true, false, 0, 0);
        Estado q1 = new Estado("q1", false, true, 0, 0);
        nfa.agregarEstado(q0);
        nfa.agregarEstado(q1);
        nfa.agregarTransicion(new Transicion(q0, "lambda", q1));

        AutomataJsonRepository repository = new AutomataJsonRepository();
        Path archivo = Files.createTempFile("automata-epsilon-", ".json");
        try {
            repository.guardar(archivo, nfa);
            Automata cargado = repository.cargar(archivo);

            assertEquals(1, cargado.getTransiciones().size());
            assertEquals("ε", cargado.getTransiciones().get(0).getSimbolo());
            assertTrue(cargado.getAlfabeto().stream().noneMatch(s -> s.equalsIgnoreCase("epsilon") || s.equals("ε")));
            assertTrue(evaluator.evaluar(cargado, "", false).isAceptada());
        } finally {
            Files.deleteIfExists(archivo);
        }
    }
}
